'use client';

import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import {
  Plus, Wallet, TrendUp, TrendDown, CreditCard,
  PiggyBank, ChartBar, PencilSimple, TrashSimple, Eye, EyeSlash,
  DotsThree, ArrowsClockwise
} from '@phosphor-icons/react';
import { formatCurrency, ACCOUNT_COLORS, ACCOUNT_ICONS } from '@/lib/utils';
import { toast } from 'sonner';
import type { Account, AccountFormData, AccountType } from '@/types';
import { IconDisplay } from '@/components/ui/icon-picker';

const ACCOUNT_TYPES: { value: AccountType; label: string; icon: string }[] = [
  { value: 'cash', label: 'Cash', icon: 'Money' },
  { value: 'checking', label: 'Checking', icon: 'Bank' },
  { value: 'savings', label: 'Savings', icon: 'PiggyBank' },
  { value: 'credit', label: 'Credit Card', icon: 'CreditCard' },
  { value: 'investment', label: 'Investment', icon: 'TrendUp' },
  { value: 'loan', label: 'Loan', icon: 'Receipt' },
  { value: 'other', label: 'Other', icon: 'Wallet' },
];

export default function AccountsPage() {
  const [accounts, setAccounts] = useState<(Account & { subaccounts?: Account[] })[]>([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editingAccount, setEditingAccount] = useState<Account | null>(null);
  const [form, setForm] = useState<AccountFormData>({
    name: '', type: 'cash', icon: '≡ƒÆ░', color: '#10b981',
    currency: 'USD', initial_balance: '0', description: '', parent_id: '',
  });
  const [saving, setSaving] = useState(false);

  useEffect(() => { fetchAccounts(); }, []);

  const fetchAccounts = async () => {
    setLoading(true);
    try {
      const res = await fetch('/api/accounts');
      const data = await res.json();
      setAccounts(data.data || []);
    } catch { toast.error('Failed to load accounts'); }
    finally { setLoading(false); }
  };

  const saveAccount = async () => {
    if (!form.name.trim()) { toast.error('Account name required'); return; }
    setSaving(true);
    try {
      const method = editingAccount ? 'PUT' : 'POST';
      const url = editingAccount ? `/api/accounts/${editingAccount.id}` : '/api/accounts';
      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(form),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error);

      if (editingAccount) {
        toast.success('Account updated');
      } else {
        toast.success('Account created');
      }
      fetchAccounts();
      setShowForm(false);
      setEditingAccount(null);
      setForm({ name: '', type: 'cash', icon: '≡ƒÆ░', color: '#10b981', currency: 'USD', initial_balance: '0', description: '', parent_id: '' });
    } catch (e: unknown) {
      toast.error(e instanceof Error ? e.message : 'Failed to save');
    } finally { setSaving(false); }
  };

  const deleteAccount = async (id: string) => {
    if (!confirm('Delete this account? All transactions will be affected. Sub-accounts will also be deleted.')) return;
    try {
      await fetch(`/api/accounts/${id}`, { method: 'DELETE' });
      toast.success('Account deleted');
      fetchAccounts();
    } catch { toast.error('Failed to delete'); }
  };

  const totalBalance = accounts.reduce((s, a) => {
    const subTotal = (a.subaccounts || []).reduce((ss, sub) => ss + sub.balance, 0);
    return s + a.balance + subTotal;
  }, 0);

  const totalInAccounts = accounts.length + accounts.reduce((s, a) => s + (a.subaccounts?.length || 0), 0);

  const groupedByType = accounts.reduce((groups, account) => {
    const type = account.type;
    if (!groups[type]) groups[type] = [];
    groups[type].push(account);
    return groups;
  }, {} as Record<string, (Account & { subaccounts?: Account[] })[]>);

  return (
    <div className="mobile-page">
      <div className="mobile-page-header">
        <div>
          <h1 className="text-3xl font-serif font-bold tracking-tight">Accounts</h1>
          <p className="text-sm text-muted-foreground mt-1 font-mono">{totalInAccounts} active accounts</p>
        </div>
        <div className="mobile-page-actions w-full sm:w-auto sm:justify-end">
          <motion.button
            onClick={fetchAccounts}
            className="btn-secondary !w-full !rounded-2xl sm:!w-auto"
            whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.98 }}
          >
            <ArrowsClockwise className="w-4 h-4" weight="bold" /> Refresh
          </motion.button>
          <motion.button
            onClick={() => setShowForm(true)}
            className="btn-primary !w-full !rounded-2xl sm:!w-auto"
            whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.98 }}
          >
            <Plus className="w-4 h-4" weight="bold" /> Add Account
          </motion.button>
        </div>
      </div>

      <motion.div
        className="mobile-hero-card relative overflow-hidden text-white"
        style={{
          background: 'linear-gradient(135deg, #10b981 0%, #059669 50%, #047857 100%)',
          boxShadow: '0 8px 32px hsl(160 84% 39% / 0.25)',
        }}
        initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}
      >
        <div className="absolute top-0 right-0 w-64 h-64 rounded-full blur-[80px] bg-white/10" />
        <div className="relative z-10">
          <p className="text-emerald-100 text-sm font-medium mb-1.5">Total Net Worth</p>
          <div className="text-4xl sm:text-5xl font-serif font-bold tracking-tight mb-5 editorial-number">
            {formatCurrency(totalBalance, 'USD')}
          </div>
          <div className="grid grid-cols-3 gap-3 text-sm text-emerald-100 font-mono">
            <span>{accounts.filter(a => a.balance >= 0).length} positive</span>
            <span>{accounts.filter(a => a.balance < 0).length} negative</span>
            <span>{accounts.length} total</span>
          </div>
        </div>
      </motion.div>

      {/* Account Groups */}
      {loading ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
          {[...Array(4)].map((_, i) => (
            <div key={i} className="glass-card p-5 h-28 shimmer-bg" />
          ))}
        </div>
      ) : accounts.length === 0 ? (
        <div className="text-center py-20">
          <Wallet className="w-12 h-12 text-muted-foreground mx-auto mb-3" weight="light" />
          <h3 className="font-serif font-semibold text-lg mb-1.5">No accounts yet</h3>
          <p className="text-sm text-muted-foreground mb-5">Add your first financial account to get started</p>
          <button onClick={() => setShowForm(true)} className="btn-primary !rounded-xl">
            Add Account
          </button>
        </div>
      ) : (
        Object.entries(groupedByType).map(([type, accts]) => (
          <div key={type}>
            <div className="flex items-center gap-3 mb-3">
              <span className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">
                {ACCOUNT_TYPES.find(t => t.value === type)?.label || type}
              </span>
              <div className="flex-1 h-px" style={{ background: 'hsl(var(--foreground) / 0.04)' }} />
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {accts.map((account, i) => (
                <motion.div
                  key={account.id}
                  className="glass-card overflow-hidden"
                  initial={{ opacity: 0, y: 15 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: i * 0.05 }}
                >
                  <div className="p-5 group">
                    <div className="flex items-start justify-between mb-4">
                      <div className="flex items-center gap-2.5">
                        <div className="w-11 h-11 rounded-xl flex items-center justify-center text-xl"
                          style={{ background: `${account.color}15`, color: account.color }}>
                          <IconDisplay name={account.icon} className="w-5 h-5" />
                        </div>
                        <div>
                          <div className="font-semibold text-sm">{account.name}</div>
                          <div className="text-xs text-muted-foreground capitalize">{account.type}</div>
                        </div>
                      </div>
                      <div className="flex items-center gap-0.5 opacity-100 transition-opacity md:opacity-0 md:group-hover:opacity-100">
                        <button onClick={() => { setForm({
                          name: '', type: account.type, icon: '≡ƒÅª', color: account.color, currency: account.currency,
                          initial_balance: '0', description: '', parent_id: account.id
                        }); setShowForm(true); }}
                          className="p-1.5 rounded-lg hover:bg-foreground/[0.04] text-muted-foreground hover:text-emerald-500 transition-colors" title="Add Sub-account">
                          <Plus className="w-3.5 h-3.5" weight="regular" />
                        </button>
                        <button onClick={() => { setEditingAccount(account); setForm({
                          name: account.name, type: account.type, icon: account.icon,
                          color: account.color, currency: account.currency,
                          initial_balance: (account.initial_balance / 100).toString(),
                          description: account.description || '', parent_id: account.parent_id || '',
                        }); setShowForm(true); }}
                          className="p-1.5 rounded-lg hover:bg-foreground/[0.04] text-muted-foreground hover:text-foreground transition-colors">
                          <PencilSimple className="w-3.5 h-3.5" weight="light" />
                        </button>
                        <button onClick={() => deleteAccount(account.id)}
                          className="p-1.5 rounded-lg hover:bg-red-500/10 text-muted-foreground hover:text-red-400 transition-colors">
                          <TrashSimple className="w-3.5 h-3.5" weight="light" />
                        </button>
                      </div>
                    </div>

                    <div className={`text-2xl font-serif font-bold editorial-number ${account.balance >= 0 ? 'text-foreground' : 'text-red-400'}`}>
                      {formatCurrency(account.balance, account.currency)}
                    </div>
                    <div className="flex items-center justify-between mt-3">
                      <span className="text-xs text-muted-foreground font-mono">{account.currency}</span>
                      <div className="h-1.5 flex-1 mx-3 rounded-full overflow-hidden" style={{ background: 'hsl(var(--foreground) / 0.04)' }}>
                        <motion.div
                          className="h-full rounded-full"
                          style={{ background: account.color }}
                          initial={{ width: 0 }}
                          animate={{ width: account.balance > 0 ? `${Math.min((account.balance / Math.max(...accounts.map(a => a.balance))) * 100, 100)}%` : '0%' }}
                          transition={{ duration: 0.8, delay: i * 0.05, ease: [0.4, 0, 0.2, 1] }}
                        />
                      </div>
                      {account.is_hidden && <EyeSlash className="w-3 h-3 text-muted-foreground" weight="light" />}
                    </div>
                  </div>

                  {account.subaccounts && account.subaccounts.length > 0 && (
                    <div className="px-5 py-3 space-y-2" style={{ borderTop: '1px solid hsl(var(--foreground) / 0.04)', background: 'hsl(var(--foreground) / 0.015)' }}>
                      {account.subaccounts.map(sub => (
                        <div key={sub.id} className="flex items-center justify-between group/sub">
                          <div className="flex items-center gap-2">
                            <div className="w-6 h-6 rounded-lg flex items-center justify-center text-xs" style={{ background: `${sub.color}15`, color: sub.color }}>
                              <IconDisplay name={sub.icon} className="w-3.5 h-3.5" />
                            </div>
                            <span className="text-xs font-medium">{sub.name}</span>
                          </div>
                          <div className="flex items-center gap-2">
                            <span className={`text-xs font-serif font-semibold editorial-number ${sub.balance >= 0 ? 'text-foreground' : 'text-red-400'}`}>
                              {formatCurrency(sub.balance, sub.currency)}
                            </span>
                            <div className="flex items-center opacity-100 transition-opacity md:opacity-0 md:group-hover/sub:opacity-100">
                              <button onClick={() => { setEditingAccount(sub); setForm({
                                name: sub.name, type: sub.type, icon: sub.icon, color: sub.color, currency: sub.currency,
                                initial_balance: (sub.initial_balance / 100).toString(), description: sub.description || '', parent_id: account.id,
                              }); setShowForm(true); }} className="p-1 hover:bg-foreground/[0.04] rounded-lg text-muted-foreground"><PencilSimple className="w-3 h-3" weight="light" /></button>
                              <button onClick={() => deleteAccount(sub.id)} className="p-1 hover:bg-red-500/10 rounded-lg text-muted-foreground"><TrashSimple className="w-3 h-3" weight="light" /></button>
                            </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </motion.div>
              ))}
            </div>
          </div>
        ))
      )}

      {/* Add/Edit Account Modal ΓÇö Glass */}
      {showForm && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4"
          style={{ background: 'hsl(var(--background) / 0.6)', backdropFilter: 'blur(16px)' }}
          onClick={() => setShowForm(false)}>
          <motion.div
            className="w-full max-w-md float-panel p-6"
            initial={{ opacity: 0, scale: 0.95, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            transition={{ duration: 0.25, ease: [0.4, 0, 0.2, 1] }}
            onClick={e => e.stopPropagation()}
          >
            <h2 className="text-lg font-serif font-semibold mb-6">{editingAccount ? 'Edit Account' : 'New Account'}</h2>

            <div className="space-y-4">
              <div>
                <label className="text-sm font-medium mb-1.5 block">Account Name *</label>
                <input value={form.name} onChange={e => setForm(f => ({ ...f, name: e.target.value }))}
                  className="w-full px-3.5 py-2.5 rounded-xl text-sm focus:outline-none input-animated"
                  style={{ border: '1px solid hsl(var(--foreground) / 0.06)', background: 'hsl(var(--foreground) / 0.02)' }}
                  placeholder="e.g. BDO Savings" />
              </div>

              <div>
                <label className="text-sm font-medium mb-1.5 block">Account Type</label>
                <div className="grid grid-cols-4 gap-2">
                  {ACCOUNT_TYPES.map(t => (
                    <button key={t.value} onClick={() => setForm(f => ({ ...f, type: t.value, icon: t.icon }))}
                      className={`flex flex-col items-center gap-1 p-2.5 rounded-xl text-xs transition-all duration-200 ${
                        form.type === t.value ? 'bg-emerald-500/10 text-emerald-500' : 'text-muted-foreground hover:bg-foreground/[0.03]'
                      }`}
                      style={{ border: `1px solid ${form.type === t.value ? 'hsl(var(--primary) / 0.2)' : 'hsl(var(--foreground) / 0.04)'}` }}>
                      <span className="text-lg flex justify-center mb-1"><IconDisplay name={t.icon} className="w-5 h-5" /></span>
                      <span>{t.label}</span>
                    </button>
                  ))}
                </div>
              </div>

              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-sm font-medium mb-1.5 block">Currency</label>
                  <select value={form.currency} onChange={e => setForm(f => ({ ...f, currency: e.target.value }))}
                    className="w-full px-3.5 py-2.5 rounded-xl text-sm focus:outline-none"
                    style={{ border: '1px solid hsl(var(--foreground) / 0.06)', background: 'hsl(var(--foreground) / 0.02)' }}>
                    {['USD','PHP','EUR','GBP','JPY','INR','SGD','MYR','THB','AUD','CAD'].map(c => (
                      <option key={c} value={c}>{c}</option>
                    ))}
                  </select>
                </div>
                <div>
                  <label className="text-sm font-medium mb-1.5 block">Initial Balance</label>
                  <input type="number" value={form.initial_balance} onChange={e => setForm(f => ({ ...f, initial_balance: e.target.value }))}
                    className="w-full px-3.5 py-2.5 rounded-xl text-sm focus:outline-none font-mono"
                    style={{ border: '1px solid hsl(var(--foreground) / 0.06)', background: 'hsl(var(--foreground) / 0.02)' }}
                    placeholder="0.00" step="0.01" />
                </div>
              </div>

              <div>
                <label className="text-sm font-medium mb-1.5 block">Parent Account (Optional)</label>
                <select value={form.parent_id} onChange={e => setForm(f => ({ ...f, parent_id: e.target.value }))}
                  className="w-full px-3.5 py-2.5 rounded-xl text-sm focus:outline-none"
                  style={{ border: '1px solid hsl(var(--foreground) / 0.06)', background: 'hsl(var(--foreground) / 0.02)' }}>
                  <option value="">None (Top-Level)</option>
                  {accounts.filter(a => a.id !== editingAccount?.id).map(a => (
                    <option key={a.id} value={a.id}>{a.name}</option>
                  ))}
                </select>
              </div>

              <div>
                <label className="text-sm font-medium mb-2 block">Color</label>
                <div className="flex flex-wrap gap-2">
                  {ACCOUNT_COLORS.map(c => (
                    <button key={c} onClick={() => setForm(f => ({ ...f, color: c }))}
                      className={`w-7 h-7 rounded-full transition-all duration-200 ${form.color === c ? 'scale-125 ring-2 ring-offset-2 ring-emerald-500' : 'hover:scale-110'}`}
                      style={{ background: c }} />
                  ))}
                </div>
              </div>

              <div className="flex gap-2.5 pt-2">
                <button onClick={() => { setShowForm(false); setEditingAccount(null); }}
                  className="btn-secondary flex-1 !rounded-xl">
                  Cancel
                </button>
                <motion.button onClick={saveAccount} disabled={saving}
                  className="btn-primary flex-1 !rounded-xl disabled:opacity-60"
                  whileTap={{ scale: 0.97 }}>
                  {saving ? 'Saving...' : editingAccount ? 'Update' : 'Create Account'}
                </motion.button>
              </div>
            </div>
          </motion.div>
        </div>
      )}
    </div>
  );
}

'use client';

import { useState, useRef, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  Brain, PaperPlaneRight, CircleNotch, CheckCircle, XCircle, Sparkle,
  Calendar, CurrencyDollar, ChatCircle, Trash, Info,
  PencilSimple, FloppyDisk, X, CaretDown
} from '@phosphor-icons/react';
import { formatCurrency, formatDate, CURRENCIES } from '@/lib/utils';
import { toast } from 'sonner';
import type { AIChatMessage, ParsedTransaction } from '@/types';
import { format } from 'date-fns';

const EXAMPLE_PROMPTS = [
  "Today I spent Γé▒150 on lunch and Γé▒50 on jeep fare",
  "I spent $4.50 on coffee and $12 on groceries",
  "Received Γé▒25,000 salary today",
  "Paid Γé▒2,500 electric bill",
  "Bus fare Γé▒25, dinner Γé▒320, movie Γé▒280",
];

export default function AIAssistantPage() {
  const [messages, setMessages] = useState<AIChatMessage[]>([
    {
      id: 'welcome',
      role: 'assistant',
      content: "Hi! I'm your CashBash AI assistant. Tell me what you spent today and I'll log your transactions.\n\nTry: **\"Today I spent Γé▒150 on lunch and Γé▒50 on bus fare\"**",
      timestamp: new Date().toISOString(),
    }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [currency, setCurrency] = useState('PHP');
  const [isPro, setIsPro] = useState(false);
  const [loadingHistory, setLoadingHistory] = useState(true);
  // Pending transactions awaiting user confirmation
  const [pendingTxs, setPendingTxs] = useState<ParsedTransaction[]>([]);
  const [pendingMsgId, setPendingMsgId] = useState<string | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLTextAreaElement>(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, pendingTxs]);

  useEffect(() => {
    async function fetchHistory() {
      try {
        const res = await fetch('/api/ai/chat-history');
        if (!res.ok) throw new Error('Failed to fetch history');
        const data = await res.json();
        setIsPro(data.isPro);
        if (data.isPro && data.messages.length > 0) {
          // Format messages from DB
          const formattedMessages = data.messages.map((m: any) => ({
            id: m.id,
            role: m.role,
            content: m.content,
            timestamp: m.created_at,
            parsed_transactions: m.parsed_transactions,
            created_transactions: m.created_transactions,
          }));
          setMessages(formattedMessages);
        }
      } catch (error) {
        console.error('Failed to load chat history:', error);
      } finally {
        setLoadingHistory(false);
      }
    }
    fetchHistory();
  }, []);

  // Save message to DB helper
  const saveMessageToDB = async (msg: any) => {
    if (!isPro) return;
    try {
      await fetch('/api/ai/chat-history', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          role: msg.role,
          content: msg.content,
          parsed_transactions: msg.parsed_transactions,
          created_transactions: msg.created_transactions,
        }),
      });
    } catch (e) {
      console.error('Failed to save message to DB', e);
    }
  };

  // ΓöÇΓöÇΓöÇ Send message ΓåÆ Parse only (no auto-save) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const sendMessage = useCallback(async (text?: string) => {
    const messageText = text || input.trim();
    if (!messageText || loading) return;

    const userMsg: AIChatMessage = {
      id: crypto.randomUUID(),
      role: 'user',
      content: messageText,
      timestamp: new Date().toISOString(),
    };

    setMessages(prev => [...prev, userMsg]);
    saveMessageToDB(userMsg);

    setInput('');
    setLoading(true);
    setPendingTxs([]);
    setPendingMsgId(null);

    try {
      const res = await fetch('/api/ai/parse', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ message: messageText, currency, parseOnly: true }),
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data.error || 'Failed to parse');

      const { parsed } = data;
      const txs: ParsedTransaction[] = parsed?.transactions || [];

      let responseContent: string;
      const msgId = crypto.randomUUID();

      if (txs.length > 0) {
        responseContent = parsed?.message ? `${parsed.message}\n\nI found **${txs.length} transaction${txs.length > 1 ? 's' : ''}**. Review below and click **Save** when ready:` : `I found **${txs.length} transaction${txs.length > 1 ? 's' : ''}**. Review below and click **Save** when ready:`;
        setPendingTxs(txs);
        setPendingMsgId(msgId);
      } else {
        responseContent = parsed?.message || "I couldn't find any transactions in that message. Try something like: \"I spent Γé▒100 on coffee\"";
      }

      const assistantMsg: AIChatMessage = {
        id: msgId,
        role: 'assistant',
        content: responseContent,
        timestamp: new Date().toISOString(),
        parsed_transactions: txs,
      };

      setMessages(prev => [...prev, assistantMsg]);
      saveMessageToDB(assistantMsg);

      if (parsed?.suggestions?.length > 0) {
        toast.info(parsed.suggestions[0], { duration: 5000 });
      }
    } catch {
      const errorMsg: AIChatMessage = {
        id: crypto.randomUUID(),
        role: 'assistant',
        content: "Sorry, something went wrong. Make sure the AI service is running and try again.",
        timestamp: new Date().toISOString(),
      };
      setMessages(prev => [...prev, errorMsg]);
      toast.error('AI parsing failed');
    } finally {
      setLoading(false);
      inputRef.current?.focus();
    }
  }, [input, loading, currency]);

  // ΓöÇΓöÇΓöÇ Confirm & Save pending transactions ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const confirmAndSave = async () => {
    if (pendingTxs.length === 0 || saving) return;
    setSaving(true);

    try {
      const payload = pendingTxs.map(tx => ({
        type: tx.category_type,
        amount: (tx.amount / 100).toFixed(2), // API expects dollars, not cents
        currency: tx.currency,
        description: tx.description,
        category_name: tx.category_name,
        transaction_date: tx.transaction_date,
        confidence: tx.confidence,
      }));

      const res = await fetch('/api/transactions/bulk', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ transactions: payload }),
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data.error || 'Failed to save');

      // Update the assistant message to show success
      setMessages(prev => {
        const updated = prev.map(m =>
          m.id === pendingMsgId
            ? { ...m, content: `Γ£à Saved **${data.count} transaction${data.count !== 1 ? 's' : ''}** successfully!`, created_transactions: data.created }
            : m
        );
        // Save the updated assistant message with the created transactions to DB
        const msgToSave = updated.find(m => m.id === pendingMsgId);
        if (msgToSave) saveMessageToDB(msgToSave);
        return updated;
      });

      toast.success(`${data.count} transaction${data.count !== 1 ? 's' : ''} saved!`);
      setPendingTxs([]);
      setPendingMsgId(null);
      // Signal dashboard to refresh its data
      if (typeof window !== 'undefined') {
        window.dispatchEvent(new CustomEvent('dashboardRefresh', { detail: { count: data.count } }));
      }
    } catch {
      toast.error('Failed to save transactions');
    } finally {
      setSaving(false);
    }
  };

  // ΓöÇΓöÇΓöÇ Discard pending ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const discardPending = () => {
    setPendingTxs([]);
    setPendingMsgId(null);
    setMessages(prev => prev.map(m =>
      m.id === pendingMsgId
        ? { ...m, content: 'Transactions discarded. Tell me what else you spent!' }
        : m
    ));
  };

  // ΓöÇΓöÇΓöÇ Edit a pending transaction ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const updatePendingTx = (index: number, field: keyof ParsedTransaction, value: string | number) => {
    setPendingTxs(prev => prev.map((tx, i) => {
      if (i !== index) return tx;
      if (field === 'amount') return { ...tx, amount: Math.round(parseFloat(String(value)) * 100) };
      return { ...tx, [field]: value };
    }));
  };

  const removePendingTx = (index: number) => {
    setPendingTxs(prev => prev.filter((_, i) => i !== index));
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  const clearChat = () => {
    setPendingTxs([]);
    setPendingMsgId(null);
    setMessages([{
      id: 'welcome',
      role: 'assistant',
      content: "Chat cleared! Tell me what you spent and I'll log it for you.",
      timestamp: new Date().toISOString(),
    }]);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-8rem)]">
      {/* Header */}
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-primary/10 flex items-center justify-center">
            <Brain className="w-5 h-5 text-primary" />
          </div>
          <div>
            <h1 className="text-xl font-bold">AI Assistant</h1>
            <p className="text-xs text-muted-foreground">Tell me what you spent ┬╖ review before saving</p>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <select
            value={currency}
            onChange={(e) => setCurrency(e.target.value)}
            aria-label="Select currency"
            className="text-xs px-2.5 py-1.5 rounded-lg border border-input bg-background focus:outline-none focus:ring-2 focus:ring-primary/20"
          >
            {Object.values(CURRENCIES).map(c => (
              <option key={c.code} value={c.code}>{c.symbol} {c.code}</option>
            ))}
          </select>
          <motion.button
            onClick={clearChat}
            className="p-2 rounded-lg border border-input hover:bg-muted transition-colors text-muted-foreground"
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
            title="Clear chat"
            aria-label="Clear chat history"
          >
            <Trash className="w-3.5 h-3.5" />
          </motion.button>
        </div>
      </div>

      {/* Info banner */}
      <motion.div
        className="rounded-xl border border-blue-200 dark:border-blue-800 bg-blue-50 dark:bg-blue-950/30 p-3 mb-4 flex flex-col sm:flex-row sm:items-start gap-3 justify-between"
        initial={{ opacity: 0, y: -10 }}
        animate={{ opacity: 1, y: 0 }}
      >
        <div className="flex items-start gap-3">
          <Info className="w-4 h-4 text-blue-600 mt-0.5 shrink-0" />
          <p className="text-xs text-blue-700 dark:text-blue-400">
            <strong>How it works:</strong> Describe your spending naturally ΓåÆ AI parses amounts, categories & dates ΓåÆ <strong>you review & confirm</strong> ΓåÆ saved to your account.
          </p>
        </div>
        {!isPro && !loadingHistory && (
          <div className="shrink-0">
            <span className="text-[10px] font-semibold bg-blue-200/50 dark:bg-blue-900/50 text-blue-800 dark:text-blue-300 px-2 py-1 rounded-full">
              Ephemeral Chat (Pro to Save)
            </span>
          </div>
        )}
      </motion.div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto scrollbar-thin space-y-4 pb-4">
        <AnimatePresence initial={false}>
          {messages.map((msg) => (
            <motion.div
              key={msg.id}
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0 }}
              className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
            >
              <div className={`max-w-[85%] ${msg.role === 'user' ? 'ml-8' : 'mr-8'}`}>
                {msg.role === 'assistant' && (
                  <div className="flex items-center gap-1.5 mb-1.5">
                    <div className="w-5 h-5 rounded-full bg-primary/20 flex items-center justify-center">
                      <Sparkle className="w-5 h-5 text-primary" weight="duotone" />
                    </div>
                    <span className="text-xs font-medium text-muted-foreground">CashBash AI</span>
                    <span className="text-[10px] text-muted-foreground/50">
                      {format(new Date(msg.timestamp), 'HH:mm')}
                    </span>
                  </div>
                )}

                <div className={`rounded-2xl px-4 py-3 text-sm leading-relaxed ${
                  msg.role === 'user'
                    ? 'bg-primary text-primary-foreground rounded-tr-sm'
                    : 'bg-muted rounded-tl-sm'
                }`}>
                  {msg.content.split('\n').map((line, i) => (
                    <p key={i} className={i > 0 ? 'mt-2' : ''}>
                      {line.split(/\*\*(.+?)\*\*/).map((part, j) =>
                        j % 2 === 1 ? <strong key={j}>{part}</strong> : part
                      )}
                    </p>
                  ))}
                </div>

                {/* Show saved transactions summary */}
                {msg.created_transactions && msg.created_transactions.length > 0 && (
                  <div className="mt-2 space-y-1">
                    {msg.created_transactions.map((tx: any, i: number) => (
                      <div key={i} className="flex items-center gap-2 px-3 py-1.5 rounded-lg border border-emerald-200 dark:border-emerald-800 bg-emerald-50 dark:bg-emerald-950/30 text-xs">
                        <CheckCircle className="w-3.5 h-3.5 text-emerald-500 mt-0.5 shrink-0" weight="fill" />
                        <span className="truncate flex-1">{tx.description}</span>
                        <span className="font-semibold text-emerald-600">{formatCurrency(tx.amount, tx.currency)}</span>
                      </div>
                    ))}
                  </div>
                )}

                {msg.role === 'user' && (
                  <div className="flex justify-end mt-1">
                    <span className="text-[10px] text-muted-foreground/50">
                      {format(new Date(msg.timestamp), 'HH:mm')}
                    </span>
                  </div>
                )}
              </div>
            </motion.div>
          ))}
        </AnimatePresence>

        {loading && (
          <motion.div className="flex justify-start" initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
            <div className="bg-muted rounded-2xl rounded-tl-sm px-4 py-3">
              <div className="flex items-center gap-2">
                <CircleNotch className="w-5 h-5 animate-spin" />
                <span className="text-xs text-muted-foreground">Analyzing your spending...</span>
              </div>
            </div>
          </motion.div>
        )}

        <div ref={messagesEndRef} />
      </div>

      {/* ΓöÇΓöÇΓöÇ Pending Transactions Confirmation Panel ΓöÇΓöÇΓöÇ */}
      <AnimatePresence>
        {pendingTxs.length > 0 && (
          <motion.div
            className="mb-3 rounded-2xl border border-primary/20 glass-card shadow-lg overflow-hidden"
            initial={{ opacity: 0, y: 20, height: 0 }}
            animate={{ opacity: 1, y: 0, height: 'auto' }}
            exit={{ opacity: 0, y: 20, height: 0 }}
          >
            <div className="px-4 py-3 border-b border-border bg-muted/30 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <PencilSimple className="w-4 h-4 text-primary" />
                <span className="text-sm font-semibold">Review & Confirm ({pendingTxs.length})</span>
              </div>
              <button onClick={discardPending} className="text-xs text-muted-foreground hover:text-foreground transition-colors">
                Discard all
              </button>
            </div>

            <div className="divide-y divide-border max-h-60 overflow-y-auto">
              {pendingTxs.map((tx, i) => (
                <EditableTransactionRow
                  key={i}
                  tx={tx}
                  index={i}
                  onUpdate={updatePendingTx}
                  onRemove={removePendingTx}
                />
              ))}
            </div>

            <div className="px-4 py-3 border-t border-border bg-muted/30 flex items-center justify-between">
              <div className="text-xs text-muted-foreground">
                Total: <strong className="text-foreground">
                  {formatCurrency(pendingTxs.reduce((s, t) => s + t.amount, 0), pendingTxs[0]?.currency || currency)}
                </strong>
              </div>
              <div className="flex items-center gap-2">
                <button onClick={discardPending}
                  className="px-3 py-1.5 rounded-lg border border-input text-xs font-medium hover:bg-muted transition-colors">
                  Cancel
                </button>
                <motion.button
                  onClick={confirmAndSave}
                  disabled={saving || pendingTxs.length === 0}
                  className="flex items-center gap-1.5 px-4 py-1.5 rounded-lg bg-primary text-primary-foreground text-xs font-semibold hover:bg-primary/90 disabled:opacity-50 transition-all"
                  whileTap={{ scale: 0.97 }}
                >
                  {saving ? <CircleNotch className="w-3.5 h-3.5 animate-spin" /> : <FloppyDisk className="w-3.5 h-3.5" />}
                  {saving ? 'Saving...' : `Save ${pendingTxs.length} transaction${pendingTxs.length > 1 ? 's' : ''}`}
                </motion.button>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Example prompts */}
      {messages.length <= 2 && pendingTxs.length === 0 && (
        <div className="mb-3">
          <p className="text-xs text-muted-foreground mb-2 flex items-center gap-1.5">
            <Sparkle className="w-3 h-3" /> Try these examples:
          </p>
          <div className="flex flex-wrap gap-2">
            {EXAMPLE_PROMPTS.map((prompt) => (
              <motion.button
                key={prompt}
                onClick={() => sendMessage(prompt)}
                className="text-xs px-3 py-1.5 rounded-full border border-input bg-background hover:border-primary/50 hover:bg-primary/5 transition-colors"
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.97 }}
              >
                {prompt}
              </motion.button>
            ))}
          </div>
        </div>
      )}

      {/* Input area */}
      <div className="relative">
        <div className="flex items-end gap-2 p-3 glass-card focus-within:ring-2 focus-within:ring-primary/20 focus-within:border-primary transition-all">
          <textarea
            ref={inputRef}
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Tell me what you spent... (Enter to send, Shift+Enter for new line)"
            className="flex-1 resize-none bg-transparent text-sm focus:outline-none placeholder:text-muted-foreground max-h-32 scrollbar-thin"
            rows={1}
            disabled={loading || saving}
          />
          <motion.button
            onClick={() => sendMessage()}
            disabled={!input.trim() || loading || saving}
            className="shrink-0 w-9 h-9 rounded-xl bg-primary text-primary-foreground flex items-center justify-center disabled:opacity-50 hover:bg-primary/90 transition-colors"
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
          >
            {loading ? <CircleNotch className="w-4 h-4 animate-spin" /> : <PaperPlaneRight className="w-4 h-4" weight="fill" />}
          </motion.button>
        </div>
        <p className="text-[10px] text-muted-foreground mt-1.5 text-center">
          AI may make mistakes. Always review parsed transactions before saving.
        </p>
      </div>
    </div>
  );
}

// ΓöÇΓöÇΓöÇ Editable Transaction Row ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function EditableTransactionRow({
  tx,
  index,
  onUpdate,
  onRemove,
}: {
  tx: ParsedTransaction;
  index: number;
  onUpdate: (index: number, field: keyof ParsedTransaction, value: string | number) => void;
  onRemove: (index: number) => void;
}) {
  const [editing, setEditing] = useState(false);

  return (
    <motion.div
      className="flex items-center gap-3 px-4 py-2.5 hover:bg-muted/20 transition-colors"
      initial={{ opacity: 0, x: -5 }}
      animate={{ opacity: 1, x: 0 }}
      transition={{ delay: index * 0.05 }}
    >
      {/* Type badge */}
      <span className={`text-[10px] font-bold uppercase px-1.5 py-0.5 rounded ${
        tx.category_type === 'income'
          ? 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400'
          : 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400'
      }`}>
        {tx.category_type === 'income' ? 'IN' : 'OUT'}
      </span>

      {/* Description */}
      <div className="flex-1 min-w-0">
        {editing ? (
          <input
            value={tx.description}
            onChange={e => onUpdate(index, 'description', e.target.value)}
            className="w-full px-2 py-1 rounded border border-input bg-background text-xs focus:outline-none focus:ring-1 focus:ring-primary"
            autoFocus
          />
        ) : (
          <div className="flex items-center gap-1.5">
            <span className="text-sm font-medium truncate">{tx.description}</span>
            <span className="text-xs text-muted-foreground">ΓåÆ {tx.category_name}</span>
          </div>
        )}
      </div>

      {/* Amount */}
      {editing ? (
        <input
          type="number"
          step="0.01"
          value={(tx.amount / 100).toFixed(2)}
          onChange={e => onUpdate(index, 'amount', parseFloat(e.target.value) || 0)}
          className="w-20 px-2 py-1 rounded border border-input bg-background text-xs text-right focus:outline-none focus:ring-1 focus:ring-primary"
        />
      ) : (
        <span className={`text-sm font-semibold shrink-0 ${
          tx.category_type === 'income' ? 'text-emerald-600' : 'text-red-500'
        }`}>
          {tx.category_type === 'income' ? '+' : '-'}{formatCurrency(tx.amount, tx.currency)}
        </span>
      )}

      {/* Date */}
      <span className="text-[10px] text-muted-foreground shrink-0">
        {formatDate(tx.transaction_date, 'MMM d')}
      </span>

      {/* Actions */}
      <div className="flex items-center gap-0.5 shrink-0">
        <button
          onClick={() => setEditing(!editing)}
          className="p-1 rounded hover:bg-muted transition-colors text-muted-foreground hover:text-foreground"
          title={editing ? 'Done editing' : 'Edit'}
        >
          {editing ? <CheckCircle className="w-3.5 h-3.5 text-emerald-500" /> : <PencilSimple className="w-3.5 h-3.5" />}
        </button>
        <button
          onClick={() => onRemove(index)}
          className="p-1 rounded hover:bg-destructive/10 transition-colors text-muted-foreground hover:text-destructive"
          title="Remove"
        >
          <X className="w-3.5 h-3.5" />
        </button>
      </div>
    </motion.div>
  );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import dynamic from 'next/dynamic';
import { motion } from 'framer-motion';
import { CaretLeft, CaretRight } from '@phosphor-icons/react';
import { formatCurrency } from '@/lib/utils';
import { format, subMonths, addMonths } from 'date-fns';

const PieChartCard = dynamic(() => import('@/components/ui/chartjs-components').then(m => ({ default: m.PieChartCard })), { ssr: false });
const AreaChartCard = dynamic(() => import('@/components/ui/chartjs-components').then(m => ({ default: m.AreaChartCard })), { ssr: false });
const LineChartCard = dynamic(() => import('@/components/ui/chartjs-components').then(m => ({ default: m.LineChartCard })), { ssr: false });
const RadarChartCard = dynamic(() => import('@/components/ui/chartjs-components').then(m => ({ default: m.RadarChartCard })), { ssr: false });
const DoughnutChartCard = dynamic(() => import('@/components/ui/chartjs-components').then(m => ({ default: m.DoughnutChartCard })), { ssr: false });

const CHART_COLORS = [
  '#ff6b6b', '#ffa94d', '#ffd43b', '#69db7c',
  '#4dabf7', '#9775fa', '#f783ac', '#63e6be',
  '#748ffc', '#e599f7', '#a9e34b', '#38d9a9',
];

interface AnalyticsData {
  monthly: { month: string; label: string; income: number; expenses: number; net: number }[];
  daily: { date: string; label: string; income: number; expenses: number }[];
  categories: { name: string; icon: string; color: string; total: number; percentage: number; count: number }[];
}

interface Summary {
  totalIncome: number;
  totalExpenses: number;
  avgDailySpend: number;
  transactionCount: number;
}

const PERIODS = [
  { label: '7D', value: '7d' },
  { label: '1M', value: '1m' },
  { label: '3M', value: '3m' },
  { label: '6M', value: '6m' },
  { label: '1Y', value: '1y' },
];

export default function AnalyticsPage() {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [activeTab, setActiveTab] = useState<'income' | 'expenses'>('expenses');
  const [data, setData] = useState<AnalyticsData | null>(null);
  const [summary, setSummary] = useState<Summary>({ totalIncome: 0, totalExpenses: 0, avgDailySpend: 0, transactionCount: 0 });
  const [loading, setLoading] = useState(true);
  const [period, setPeriod] = useState('1m');
  const [profileCurrency, setProfileCurrency] = useState('USD');

  const fetchData = useCallback(async () => {
    setLoading(true);
    try {
      const [analyticsRes, profileRes] = await Promise.all([
        fetch(`/api/analytics?period=${period}`),
        fetch('/api/profile'),
      ]);
      const analyticsJson = await analyticsRes.json();
      const profileJson = await profileRes.json();
      if (analyticsJson.data) {
        setData(analyticsJson.data);
        setSummary(analyticsJson.summary || { totalIncome: 0, totalExpenses: 0, avgDailySpend: 0, transactionCount: 0 });
      }
      if (profileJson.data?.default_currency) {
        setProfileCurrency(profileJson.data.default_currency);
      }
    } catch {}
    setLoading(false);
  }, [period]);

  useEffect(() => { fetchData(); }, [fetchData]);

  const prevMonth = () => setCurrentDate(d => subMonths(d, 1));
  const nextMonth = () => setCurrentDate(d => addMonths(d, 1));

  const categories = data?.categories || [];
  const monthly = data?.monthly || [];
  const totalAmount = activeTab === 'expenses' ? summary.totalExpenses : summary.totalIncome;
  const netAmount = summary.totalIncome - summary.totalExpenses;
  const savingsRate = summary.totalIncome > 0 ? Math.round((netAmount / summary.totalIncome) * 100) : 0;
  const cur = profileCurrency;

  const coloredCategories = categories.map((cat, i) => ({
    ...cat,
    assignedColor: cat.color || CHART_COLORS[i % CHART_COLORS.length],
  }));

  // Health score
  const healthScore = Math.min(100, Math.max(0,
    savingsRate > 0 ? Math.round(savingsRate * 1.5 + 30) : Math.max(0, 30 + savingsRate)
  ));
  const healthLabel = healthScore >= 80 ? 'Excellent' : healthScore >= 60 ? 'Good' : healthScore >= 40 ? 'Fair' : 'Needs Work';
  const healthColor = healthScore >= 80 ? '#69db7c' : healthScore >= 60 ? '#ffd43b' : healthScore >= 40 ? '#ffa94d' : '#ff6b6b';

  // Daily spending data from categories count
  const avgDaily = summary.avgDailySpend || (summary.totalExpenses > 0 ? Math.round(summary.totalExpenses / 30) : 0);

  const fmt = (v: number) => formatCurrency(v, cur);

  return (
    <div className="space-y-0 pb-24">
      {/* ΓöÇΓöÇ Header ΓÇö month nav ΓöÇΓöÇ */}
      <div className="flex items-center justify-between px-4 py-3">
        <div className="flex items-center gap-3">
          <button onClick={prevMonth} className="p-1"><CaretLeft className="w-5 h-5" /></button>
          <span className="text-lg font-semibold">{format(currentDate, 'MMM yyyy')}</span>
          <button onClick={nextMonth} className="p-1"><CaretRight className="w-5 h-5" /></button>
        </div>
      </div>

      {/* ΓöÇΓöÇ Period pills ΓöÇΓöÇ */}
      <div className="flex gap-1 px-4 pb-3">
        {PERIODS.map(p => (
          <button key={p.value} onClick={() => setPeriod(p.value)}
            className={`flex-1 py-1.5 rounded-lg text-xs font-medium transition-all ${
              period === p.value ? 'bg-primary text-primary-foreground' : 'bg-foreground/[0.04] text-muted-foreground'
            }`}>{p.label}</button>
        ))}
      </div>

      {/* ΓöÇΓöÇ Income / Expenses tabs ΓöÇΓöÇ */}
      <div className="flex border-b border-border/30">
        <button onClick={() => setActiveTab('income')}
          className={`flex-1 py-3 text-center text-sm font-medium transition-colors ${
            activeTab === 'income' ? 'text-blue-400 border-b-2 border-blue-400' : 'text-muted-foreground'
          }`}>Income</button>
        <button onClick={() => setActiveTab('expenses')}
          className={`flex-1 py-3 text-center text-sm font-medium transition-colors ${
            activeTab === 'expenses' ? 'text-red-400 border-b-2 border-red-400' : 'text-muted-foreground'
          }`}>Expenses</button>
      </div>

      {/* ΓöÇΓöÇ 4 summary stat boxes ΓÇö always visible ΓöÇΓöÇ */}
      <div className="grid grid-cols-2 gap-px bg-border/10">
        <div className="bg-background px-4 py-3">
          <p className="text-[10px] text-muted-foreground uppercase">Total Income</p>
          <p className="text-base font-semibold text-blue-400 tabular-nums">{fmt(summary.totalIncome)}</p>
        </div>
        <div className="bg-background px-4 py-3">
          <p className="text-[10px] text-muted-foreground uppercase">Total Expenses</p>
          <p className="text-base font-semibold text-red-400 tabular-nums">{fmt(summary.totalExpenses)}</p>
        </div>
        <div className="bg-background px-4 py-3">
          <p className="text-[10px] text-muted-foreground uppercase">Net Savings</p>
          <p className={`text-base font-semibold tabular-nums ${netAmount >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
            {netAmount >= 0 ? '+' : ''}{fmt(netAmount)}
          </p>
        </div>
        <div className="bg-background px-4 py-3">
          <p className="text-[10px] text-muted-foreground uppercase">Daily Average</p>
          <p className="text-base font-semibold text-muted-foreground tabular-nums">{fmt(avgDaily)}</p>
        </div>
      </div>

      {loading ? (
        <div className="flex items-center justify-center py-20">
          <div className="w-8 h-8 border-2 border-primary/30 border-t-primary rounded-full animate-spin" />
        </div>
      ) : (
        <>
          {/* ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ PIE CHART ΓÇö always visible ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ */}
          <SectionLabel title="Category Breakdown" />
          <div className="px-4 py-4">
            {coloredCategories.length > 0 ? (
              <PieChartCard
                labels={coloredCategories.map(c => `${c.icon} ${c.name}`)}
                data={coloredCategories.map(c => c.total)}
                colors={coloredCategories.map(c => c.assignedColor)}
                height={280}
                formatValue={fmt}
              />
            ) : (
              <EmptyChart text="No category data for this period" />
            )}
          </div>

          {/* ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ CATEGORY LIST ΓÇö always visible ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ */}
          <SectionLabel title={`Categories (${coloredCategories.length})`} />
          <div>
            {coloredCategories.map((cat) => {
              const pct = totalAmount > 0 ? Math.round((cat.total / totalAmount) * 100) : 0;
              return (
                <div key={cat.name} className="flat-list-item px-4">
                  <span className="pct-badge" style={{ background: cat.assignedColor }}>{pct}%</span>
                  <span className="text-base">{cat.icon}</span>
                  <div className="flex-1 min-w-0">
                    <span className="text-sm font-medium block truncate">{cat.name}</span>
                    <span className="text-xs text-muted-foreground">{cat.count} transaction{cat.count !== 1 ? 's' : ''}</span>
                  </div>
                  <div className="text-right">
                    <span className="text-sm font-semibold tabular-nums block">{fmt(cat.total)}</span>
                    <div className="budget-bar-track mt-1" style={{ width: 60 }}>
                      <div className="budget-bar-fill" style={{ width: `${pct}%`, background: cat.assignedColor }} />
                    </div>
                  </div>
                </div>
              );
            })}
            {coloredCategories.length === 0 && <EmptyChart text="No categories yet" />}
          </div>

          {/* ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ INCOME VS EXPENSES TREND ΓÇö always visible ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ */}
          <SectionLabel title="Income vs Expenses Trend" />
          <div className="px-4 py-4">
            {monthly.length > 0 ? (
              <AreaChartCard
                labels={monthly.map(m => m.label)}
                datasets={[
                  { label: 'Income', data: monthly.map(m => m.income), borderColor: '#4dabf7', bgFrom: 'rgba(77,171,247,0.15)', bgTo: 'transparent' },
                  { label: 'Expenses', data: monthly.map(m => m.expenses), borderColor: '#ff6b6b', bgFrom: 'rgba(255,107,107,0.15)', bgTo: 'transparent' },
                ]}
                height={220}
                formatValue={fmt}
              />
            ) : (
              <EmptyChart text="Not enough data for trends yet" />
            )}
          </div>

          {/* ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ NET CASH FLOW ΓÇö always visible ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ */}
          {monthly.length > 0 && (
            <>
              <SectionLabel title="Net Cash Flow" />
              <div className="px-4 py-4">
                <LineChartCard
                  labels={monthly.map(m => m.label)}
                  data={monthly.map(m => m.income - m.expenses)}
                  color={netAmount >= 0 ? '#69db7c' : '#ff6b6b'}
                  formatValue={fmt}
                  height={180}
                />
              </div>
            </>
          )}

          {/* ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ FINANCIAL HEALTH SCORE ΓÇö always visible ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ */}
          <SectionLabel title="Financial Health Score" />
          <div className="px-4 py-4">
            <div className="flex items-center gap-5">
              <div className="relative w-20 h-20 shrink-0">
                <svg viewBox="0 0 36 36" className="w-20 h-20 -rotate-90">
                  <circle cx="18" cy="18" r="15.9" fill="none" stroke="hsl(var(--foreground) / 0.06)" strokeWidth="3" />
                  <circle cx="18" cy="18" r="15.9" fill="none" stroke={healthColor} strokeWidth="3"
                    strokeDasharray={`${healthScore} ${100 - healthScore}`} strokeLinecap="round" />
                </svg>
                <div className="absolute inset-0 flex items-center justify-center">
                  <span className="text-xl font-bold" style={{ color: healthColor }}>{healthScore}</span>
                </div>
              </div>
              <div className="flex-1">
                <p className="text-lg font-semibold" style={{ color: healthColor }}>{healthLabel}</p>
                <p className="text-xs text-muted-foreground mt-0.5">
                  {savingsRate >= 20 ? 'Great savings discipline! Keep it up.' :
                   savingsRate >= 0 ? 'Room for improvement ΓÇö try to save more.' :
                   'Spending exceeds income ΓÇö review your expenses.'}
                </p>
              </div>
            </div>

            <div className="mt-4 space-y-3">
              <HealthBar label="Savings Rate" value={Math.max(0, savingsRate)} color="#69db7c" />
              <HealthBar label="Spending Control" value={Math.min(100, Math.max(0, 100 - (summary.totalExpenses / Math.max(1, summary.totalIncome)) * 100))} color="#4dabf7" />
              <HealthBar label="Consistency" value={Math.min(100, (summary.transactionCount || 0) * 3)} color="#9775fa" />
            </div>
          </div>

          {/* ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ SPENDING RADAR ΓÇö always visible (3+ categories) ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ */}
          {coloredCategories.length >= 3 && (
            <>
              <SectionLabel title="Spending Radar" />
              <div className="px-4 py-4">
                <RadarChartCard
                  labels={coloredCategories.slice(0, 8).map(c => c.name)}
                  datasets={[{
                    label: 'Spending',
                    data: coloredCategories.slice(0, 8).map(c => c.total),
                    color: '#ff6b6b',
                  }]}
                  height={260}
                />
              </div>
            </>
          )}

          {/* ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ TOP SPENDING INSIGHTS ΓÇö CashDash unique ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ */}
          {coloredCategories.length > 0 && (
            <>
              <SectionLabel title="Top Insights" />
              <div className="px-4 py-3 space-y-2">
                {coloredCategories.slice(0, 3).map((cat, i) => {
                  const pct = totalAmount > 0 ? Math.round((cat.total / totalAmount) * 100) : 0;
                  return (
                    <div key={cat.name} className="flex items-start gap-3 py-2">
                      <span className="text-lg">{cat.icon}</span>
                      <p className="text-xs text-muted-foreground leading-relaxed">
                        <span className="font-semibold text-foreground">{cat.name}</span> accounts for{' '}
                        <span className="font-semibold" style={{ color: cat.assignedColor }}>{pct}%</span> of your{' '}
                        {activeTab} ({fmt(cat.total)}) across {cat.count} transaction{cat.count !== 1 ? 's' : ''}.
                      </p>
                    </div>
                  );
                })}
              </div>
            </>
          )}

          {/* ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ EXPENSE DOUGHNUT ΓÇö bonus chart ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ */}
          {coloredCategories.length > 0 && (
            <>
              <SectionLabel title="Expense Distribution" />
              <div className="px-4 py-4">
                <DoughnutChartCard
                  labels={coloredCategories.map(c => c.name)}
                  data={coloredCategories.map(c => c.total)}
                  colors={coloredCategories.map(c => c.assignedColor)}
                  centerValue={fmt(summary.totalExpenses)}
                  centerLabel="Total Spent"
                  height={220}
                  formatValue={fmt}
                />
              </div>
            </>
          )}
        </>
      )}
    </div>
  );
}

// ΓöÇΓöÇ Helper components ΓöÇΓöÇ

function SectionLabel({ title }: { title: string }) {
  return (
    <div className="px-4 pt-5 pb-1">
      <h3 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">{title}</h3>
    </div>
  );
}

function EmptyChart({ text }: { text: string }) {
  return <div className="text-center py-10 text-sm text-muted-foreground">{text}</div>;
}

function HealthBar({ label, value, color }: { label: string; value: number; color: string }) {
  return (
    <div className="space-y-1">
      <div className="flex items-center justify-between">
        <span className="text-xs text-muted-foreground">{label}</span>
        <span className="text-xs font-semibold" style={{ color }}>{Math.round(value)}%</span>
      </div>
      <div className="budget-bar-track">
        <div className="budget-bar-fill" style={{ width: `${Math.min(100, value)}%`, background: color }} />
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  Plus, ChartBar, Target, X, CircleNotch, FloppyDisk,
  PencilSimple, TrashSimple, Warning, CheckCircle
} from '@phosphor-icons/react';
import { formatCurrency } from '@/lib/utils';
import { toast } from 'sonner';
import { format, startOfMonth, endOfMonth } from 'date-fns';

interface Budget {
  id: string;
  name: string;
  category_id: string | null;
  amount: number;
  currency: string;
  period: string;
  icon: string;
  color: string;
  is_active: boolean;
  notes: string | null;
  // computed
  spent?: number;
  remaining?: number;
  percentage?: number;
  category?: { name: string; icon: string; color: string };
}

interface Category {
  id: string;
  name: string;
  icon: string;
  color: string;
  type: string;
}

const PERIOD_LABELS: Record<string, string> = {
  weekly: 'Weekly', monthly: 'Monthly', quarterly: 'Quarterly', yearly: 'Yearly',
};

const COLORS = ['#10b981', '#3b82f6', '#f59e0b', '#ef4444', '#a855f7', '#ec4899', '#06b6d4', '#f97316'];

export default function BudgetsPage() {
  const [budgets, setBudgets] = useState<Budget[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [loading, setLoading] = useState(true);
  const [currency, setCurrency] = useState('PHP');
  const [showForm, setShowForm] = useState(false);
  const [editingBudget, setEditingBudget] = useState<Budget | null>(null);

  const [form, setForm] = useState({
    name: '',
    category_id: '',
    amount: '',
    period: 'monthly',
    icon: '≡ƒôè',
    color: '#10b981',
    notes: '',
  });
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    loadAll();
  }, []);

  const loadAll = async () => {
    setLoading(true);
    try {
      const [budgetsRes, catRes, profileRes] = await Promise.all([
        fetch('/api/budgets').then(r => r.json()),
        fetch('/api/categories').then(r => r.json()),
        fetch('/api/profile').then(r => r.json()),
      ]);
      const cats: Category[] = (catRes.data || []).filter((c: Category) => c.type === 'expense');
      setCategories(cats);
      setCurrency(profileRes.data?.default_currency || 'PHP');

      // Compute spending for each budget
      const now = new Date();
      const monthStart = format(startOfMonth(now), 'yyyy-MM-dd');
      const monthEnd = format(endOfMonth(now), 'yyyy-MM-dd');

      const txRes = await fetch(`/api/transactions?date_from=${monthStart}&date_to=${monthEnd}&type=expense&limit=200`);
      const txData = await txRes.json();
      const transactions = txData.data || [];

      const rawBudgets: Budget[] = budgetsRes.data || [];
      const enriched = rawBudgets.map((b: Budget) => {
        const relatedTxs = b.category_id
          ? transactions.filter((t: any) => t.category_id === b.category_id)
          : transactions;
        const spent = relatedTxs.reduce((s: number, t: any) => s + t.amount, 0);
        const remaining = b.amount - spent;
        const percentage = b.amount > 0 ? Math.min(100, Math.round((spent / b.amount) * 100)) : 0;
        return { ...b, spent, remaining, percentage };
      });

      setBudgets(enriched);
    } catch (err) {
      toast.error('Failed to load budgets');
    } finally {
      setLoading(false);
    }
  };

  const openCreate = () => {
    setEditingBudget(null);
    setForm({ name: '', category_id: '', amount: '', period: 'monthly', icon: '≡ƒôè', color: '#10b981', notes: '' });
    setShowForm(true);
  };

  const openEdit = (b: Budget) => {
    setEditingBudget(b);
    setForm({
      name: b.name,
      category_id: b.category_id || '',
      amount: (b.amount / 100).toFixed(2),
      period: b.period,
      icon: b.icon,
      color: b.color,
      notes: b.notes || '',
    });
    setShowForm(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const amountNum = parseFloat(form.amount);
    if (isNaN(amountNum) || amountNum <= 0) { toast.error('Enter a valid amount'); return; }

    setSaving(true);
    try {
      const payload = {
        name: form.name || (categories.find(c => c.id === form.category_id)?.name || 'Budget'),
        category_id: form.category_id || null,
        amount: Math.round(amountNum * 100),
        currency,
        period: form.period,
        icon: form.icon,
        color: form.color,
        notes: form.notes || null,
        is_active: true,
      };

      const url = editingBudget ? `/api/budgets/${editingBudget.id}` : '/api/budgets';
      const method = editingBudget ? 'PUT' : 'POST';
      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error);

      toast.success(editingBudget ? 'Budget updated!' : 'Budget created!');
      setShowForm(false);
      loadAll();
    } catch (err: any) {
      toast.error(err.message || 'Failed to save budget');
    } finally {
      setSaving(false);
    }
  };

  const deleteBudget = async (id: string) => {
    try {
      await fetch(`/api/budgets/${id}`, { method: 'DELETE' });
      setBudgets(prev => prev.filter(b => b.id !== id));
      toast.success('Budget deleted');
    } catch {
      toast.error('Failed to delete');
    }
  };

  const totalBudgeted = budgets.reduce((s, b) => s + b.amount, 0);
  const totalSpent = budgets.reduce((s, b) => s + (b.spent || 0), 0);
  const overBudgetCount = budgets.filter(b => (b.spent || 0) > b.amount).length;

  return (
    <div className="mobile-page">
      <div className="mobile-page-header">
        <div>
          <h1 className="text-3xl font-serif font-bold tracking-tight">Budgets</h1>
          <p className="text-sm text-muted-foreground mt-1 font-mono">{format(new Date(), 'MMMM yyyy')} spending limits</p>
        </div>
        <div className="mobile-page-actions w-full sm:w-auto sm:justify-end">
          <motion.button onClick={openCreate} className="btn-primary !w-full !rounded-2xl sm:!w-auto"
            whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.98 }}>
            <Plus className="w-4 h-4" weight="bold" /> New Budget
          </motion.button>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-4 sm:grid-cols-3">
        {[
          { label: 'Total Budgeted', value: formatCurrency(totalBudgeted, currency), icon: ChartBar, color: '#3b82f6', bg: 'rgba(59,130,246,0.08)' },
          { label: 'Total Spent', value: formatCurrency(totalSpent, currency), icon: Target, color: totalSpent > totalBudgeted ? '#ef4444' : '#10b981', bg: totalSpent > totalBudgeted ? 'rgba(239,68,68,0.08)' : 'rgba(16,185,129,0.08)' },
          { label: 'Over Budget', value: `${overBudgetCount} budget${overBudgetCount !== 1 ? 's' : ''}`, icon: Warning, color: overBudgetCount > 0 ? '#f59e0b' : '#10b981', bg: overBudgetCount > 0 ? 'rgba(245,158,11,0.08)' : 'rgba(16,185,129,0.08)' },
        ].map(stat => {
          const Icon = stat.icon;
          return (
            <motion.div key={stat.label} className="stat-card" initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}>
              <div className="p-2.5 rounded-xl inline-flex mb-3" style={{ background: stat.bg }}>
                <Icon className="w-4 h-4" style={{ color: stat.color }} />
              </div>
              <div className="text-xl font-serif font-bold editorial-number">{stat.value}</div>
              <div className="text-xs text-muted-foreground mt-0.5">{stat.label}</div>
            </motion.div>
          );
        })}
      </div>

      {/* Budget List */}
      {loading ? (
        <div className="space-y-3">
          {[...Array(3)].map((_, i) => <div key={i} className="glass-card h-24 shimmer-bg rounded-2xl" />)}
        </div>
      ) : budgets.length === 0 ? (
        <motion.div className="text-center py-16" initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
          <div className="w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-4 bg-primary/5">
            <ChartBar className="w-8 h-8 text-muted-foreground" weight="light" />
          </div>
          <h3 className="font-serif font-semibold text-lg mb-2">No budgets yet</h3>
          <p className="text-sm text-muted-foreground mb-5">Set monthly spending limits per category to stay on track</p>
          <motion.button onClick={openCreate} className="btn-primary !rounded-xl" whileTap={{ scale: 0.97 }}>
            <Plus className="w-4 h-4" /> Create First Budget
          </motion.button>
        </motion.div>
      ) : (
        <div className="space-y-3">
          {budgets.map((b, i) => {
            const pct = b.percentage || 0;
            const isOver = (b.spent || 0) > b.amount;
            const isWarning = pct >= 80 && !isOver;
            const barColor = isOver ? '#ef4444' : isWarning ? '#f59e0b' : b.color;

            return (
              <motion.div key={b.id} className="glass-card p-5"
                initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}
                transition={{ delay: i * 0.05 }}>
                <div className="flex items-start gap-4">
                  {/* Icon */}
                  <div className="w-11 h-11 rounded-xl flex items-center justify-center text-xl shrink-0"
                    style={{ background: `${b.color}15` }}>
                    {b.icon}
                  </div>

                  <div className="flex-1 min-w-0">
                    <div className="flex items-center justify-between mb-1">
                      <div>
                        <span className="font-semibold text-sm">{b.name}</span>
                        <span className="ml-2 text-[10px] font-medium px-1.5 py-0.5 rounded-full bg-muted text-muted-foreground">
                          {PERIOD_LABELS[b.period]}
                        </span>
                        {isOver && (
                          <span className="ml-1.5 text-[10px] font-bold px-1.5 py-0.5 rounded-full bg-red-500/10 text-red-500">OVER</span>
                        )}
                        {isWarning && (
                          <span className="ml-1.5 text-[10px] font-bold px-1.5 py-0.5 rounded-full bg-amber-500/10 text-amber-500">WARNING</span>
                        )}
                      </div>
                      <div className="flex items-center gap-1 shrink-0">
                        <button onClick={() => openEdit(b)}
                          className="p-1.5 rounded-lg hover:bg-muted transition-colors text-muted-foreground hover:text-foreground">
                          <PencilSimple className="w-3.5 h-3.5" />
                        </button>
                        <button onClick={() => deleteBudget(b.id)}
                          className="p-1.5 rounded-lg hover:bg-red-500/10 transition-colors text-muted-foreground hover:text-red-400">
                          <TrashSimple className="w-3.5 h-3.5" />
                        </button>
                      </div>
                    </div>

                    {/* Progress bar */}
                    <div className="h-2 bg-muted rounded-full overflow-hidden mb-2">
                      <motion.div className="h-full rounded-full"
                        style={{ background: barColor }}
                        initial={{ width: 0 }}
                        animate={{ width: `${Math.min(100, pct)}%` }}
                        transition={{ delay: 0.1 + i * 0.05, duration: 0.6, ease: [0.4, 0, 0.2, 1] }} />
                    </div>

                    {/* Amounts */}
                    <div className="flex items-center justify-between text-xs">
                      <span className="text-muted-foreground">
                        Spent: <strong className="text-foreground">{formatCurrency(b.spent || 0, currency)}</strong>
                      </span>
                      <span className={`font-mono font-semibold ${isOver ? 'text-red-400' : 'text-muted-foreground'}`}>
                        {pct}% of {formatCurrency(b.amount, currency)}
                      </span>
                      <span className={`text-muted-foreground ${isOver ? 'text-red-400' : ''}`}>
                        {isOver ? 'Over by' : 'Left'}: <strong>{formatCurrency(Math.abs(b.remaining || 0), currency)}</strong>
                      </span>
                    </div>

                    {b.notes && <p className="text-[11px] text-muted-foreground mt-1.5 italic">{b.notes}</p>}
                  </div>
                </div>
              </motion.div>
            );
          })}
        </div>
      )}

      {/* Create/Edit Modal */}
      <AnimatePresence>
        {showForm && (
          <motion.div className="fixed inset-0 z-50 flex items-center justify-center"
            style={{ background: 'hsl(var(--background) / 0.7)', backdropFilter: 'blur(16px)' }}
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            onClick={() => setShowForm(false)}>
            <motion.div className="float-panel w-full max-w-md mx-4 p-6"
              initial={{ scale: 0.95, opacity: 0, y: 10 }} animate={{ scale: 1, opacity: 1, y: 0 }}
              exit={{ scale: 0.95, opacity: 0, y: 10 }}
              transition={{ duration: 0.2 }}
              onClick={e => e.stopPropagation()}>
              <div className="flex items-center justify-between mb-5">
                <h3 className="text-lg font-serif font-semibold">{editingBudget ? 'Edit Budget' : 'New Budget'}</h3>
                <button onClick={() => setShowForm(false)} className="p-1.5 rounded-lg hover:bg-muted transition-colors">
                  <X className="w-4 h-4" />
                </button>
              </div>

              <form onSubmit={handleSubmit} className="space-y-4">
                <div>
                  <label className="text-xs font-medium text-muted-foreground mb-1.5 block">Category (optional)</label>
                  <select value={form.category_id} onChange={e => {
                    const cat = categories.find(c => c.id === e.target.value);
                    setForm(f => ({
                      ...f,
                      category_id: e.target.value,
                      icon: cat ? cat.icon : f.icon,
                      color: cat ? cat.color : f.color,
                      name: cat ? cat.name : f.name,
                    }));
                  }}
                    className="w-full px-3 py-2.5 rounded-xl text-sm border border-input bg-background focus:outline-none focus:ring-2 focus:ring-primary/20">
                    <option value="">All Expenses (no category limit)</option>
                    {categories.map(c => <option key={c.id} value={c.id}>{c.icon} {c.name}</option>)}
                  </select>
                </div>

                <div>
                  <label className="text-xs font-medium text-muted-foreground mb-1.5 block">Budget Name</label>
                  <input value={form.name} onChange={e => setForm(f => ({ ...f, name: e.target.value }))}
                    className="w-full px-3 py-2.5 rounded-xl text-sm border border-input bg-background focus:outline-none focus:ring-2 focus:ring-primary/20"
                    placeholder="e.g. Food & Dining" />
                </div>

                <div className="grid grid-cols-2 gap-3">
                  <div>
                    <label className="text-xs font-medium text-muted-foreground mb-1.5 block">Limit Amount *</label>
                    <input type="number" step="0.01" required value={form.amount}
                      onChange={e => setForm(f => ({ ...f, amount: e.target.value }))}
                      className="w-full px-3 py-2.5 rounded-xl text-sm border border-input bg-background focus:outline-none focus:ring-2 focus:ring-primary/20"
                      placeholder="5000" />
                  </div>
                  <div>
                    <label className="text-xs font-medium text-muted-foreground mb-1.5 block">Period</label>
                    <select value={form.period} onChange={e => setForm(f => ({ ...f, period: e.target.value }))}
                      className="w-full px-3 py-2.5 rounded-xl text-sm border border-input bg-background focus:outline-none">
                      {Object.entries(PERIOD_LABELS).map(([v, l]) => <option key={v} value={v}>{l}</option>)}
                    </select>
                  </div>
                </div>

                <div>
                  <label className="text-xs font-medium text-muted-foreground mb-1.5 block">Color</label>
                  <div className="flex gap-2 flex-wrap">
                    {COLORS.map(c => (
                      <button key={c} type="button" onClick={() => setForm(f => ({ ...f, color: c }))}
                        className={`w-7 h-7 rounded-full transition-all ${form.color === c ? 'ring-2 ring-offset-2 ring-foreground scale-110' : ''}`}
                        style={{ background: c }} />
                    ))}
                  </div>
                </div>

                <div>
                  <label className="text-xs font-medium text-muted-foreground mb-1.5 block">Notes (optional)</label>
                  <input value={form.notes} onChange={e => setForm(f => ({ ...f, notes: e.target.value }))}
                    className="w-full px-3 py-2.5 rounded-xl text-sm border border-input bg-background focus:outline-none focus:ring-2 focus:ring-primary/20"
                    placeholder="Any notes about this budget..." />
                </div>

                <div className="flex gap-2.5 pt-2">
                  <button type="button" onClick={() => setShowForm(false)} className="btn-secondary flex-1 !rounded-xl">Cancel</button>
                  <motion.button type="submit" disabled={saving} className="btn-primary flex-1 !rounded-xl disabled:opacity-50" whileTap={{ scale: 0.97 }}>
                    {saving ? <CircleNotch className="w-4 h-4 animate-spin" /> : <FloppyDisk className="w-4 h-4" />}
                    {saving ? 'Saving...' : editingBudget ? 'Update' : 'Create Budget'}
                  </motion.button>
                </div>
              </form>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  FolderOpen, Plus, Edit3, Trash2, Tag, ChevronDown, ChevronRight
} from 'lucide-react';
import { ACCOUNT_COLORS } from '@/lib/utils';
import { toast } from 'sonner';
import type { Category, CategoryFormData, CategoryType } from '@/types';
import { EmojiPicker } from '@/components/ui/emoji-picker-mart';

export default function CategoriesPage() {
  const [categories, setCategories] = useState<Category[]>([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editingCategory, setEditingCategory] = useState<Category | null>(null);
  const [form, setForm] = useState<CategoryFormData>({
    name: '', type: 'expense', icon: '≡ƒôª', color: '#6366f1', parent_id: ''
  });
  const [saving, setSaving] = useState(false);
  const [expandedParents, setExpandedParents] = useState<Record<string, boolean>>({});

  useEffect(() => { fetchCategories(); }, []);

  const fetchCategories = async () => {
    setLoading(true);
    try {
      const res = await fetch('/api/categories');
      const data = await res.json();
      setCategories(data.data || []);
      // Auto-expand all by default
      const expanded: Record<string, boolean> = {};
      (data.data || []).forEach((c: Category) => { expanded[c.id] = true; });
      setExpandedParents(expanded);
    } catch { toast.error('Failed to load categories'); }
    finally { setLoading(false); }
  };

  const saveCategory = async () => {
    if (!form.name.trim()) { toast.error('Category name required'); return; }
    setSaving(true);
    try {
      const method = editingCategory ? 'PUT' : 'POST';
      const url = editingCategory ? `/api/categories/${editingCategory.id}` : '/api/categories';
      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          ...form,
          parent_id: form.parent_id === '' ? null : form.parent_id
        }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error);

      toast.success(editingCategory ? 'Category updated' : 'Category created');
      fetchCategories(); // Re-fetch to get correct nested structure
      setShowForm(false);
      setEditingCategory(null);
      resetForm();
    } catch (e: any) {
      toast.error(e.message || 'Failed to save');
    } finally { setSaving(false); }
  };

  const deleteCategory = async (id: string) => {
    if (!confirm('Delete this category? Transactions using it will lose their category.')) return;
    try {
      const res = await fetch(`/api/categories/${id}`, { method: 'DELETE' });
      if (!res.ok) throw new Error('Failed to delete');
      toast.success('Category deleted');
      fetchCategories();
    } catch { toast.error('Failed to delete'); }
  };

  const resetForm = () => {
    setForm({ name: '', type: 'expense', icon: '≡ƒôª', color: '#6366f1', parent_id: '' });
  };

  const toggleExpand = (id: string) => {
    setExpandedParents(prev => ({ ...prev, [id]: !prev[id] }));
  };

  const groupedByType = categories.reduce((groups, cat) => {
    if (!groups[cat.type]) groups[cat.type] = [];
    groups[cat.type].push(cat);
    return groups;
  }, {} as Record<string, Category[]>);

  // Flatten for parent dropdown (only parents of the same type)
  const getParentOptions = (type: CategoryType) => {
    return categories.filter(c => c.type === type); // they are already top-level from API
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <p className="text-[11px] font-medium uppercase tracking-[0.24em] text-muted-foreground">Structure</p>
          <h1 className="mt-1 text-2xl font-semibold text-foreground">Categories</h1>
          <p className="mt-0.5 text-sm text-muted-foreground">Manage income and expense categories, including sub-categories.</p>
        </div>
        <motion.button
          onClick={() => { resetForm(); setShowForm(true); }}
          className="inline-flex items-center justify-center gap-2 rounded-2xl bg-primary px-4 py-3 text-sm font-medium text-primary-foreground hover:bg-primary/90"
          whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.98 }}
        >
          <Plus className="w-4 h-4" /> Add Category
        </motion.button>
      </div>

      {loading ? (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="rounded-xl border border-border bg-card p-5 h-64 shimmer-bg" />
          <div className="rounded-xl border border-border bg-card p-5 h-64 shimmer-bg" />
        </div>
      ) : categories.length === 0 ? (
        <div className="text-center py-16 rounded-2xl border border-border bg-card shadow-soft">
          <FolderOpen className="w-12 h-12 text-muted-foreground mx-auto mb-3" />
          <h3 className="font-semibold mb-1">No categories yet</h3>
          <p className="text-sm text-muted-foreground mb-4">Add your first category to start organizing transactions</p>
          <button onClick={() => { resetForm(); setShowForm(true); }} className="px-4 py-2 rounded-lg bg-primary text-primary-foreground text-sm font-medium">
            Add Category
          </button>
        </div>
      ) : (
        <div className="grid grid-cols-1 gap-4 xl:grid-cols-2 xl:gap-6">
          {['expense', 'income', 'transfer'].map(type => {
            const typeCats = groupedByType[type] || [];
            if (typeCats.length === 0) return null;
            return (
              <div key={type} className="glass-card overflow-hidden flex flex-col">
                <div className="flex items-center gap-2 border-b border-border/70 bg-foreground/[0.015] px-5 py-4">
                  <div className={`w-2 h-2 rounded-full ${type === 'income' ? 'bg-emerald-500' : type === 'expense' ? 'bg-red-500' : 'bg-blue-500'}`} />
                  <h2 className="font-semibold capitalize text-lg">{type} Categories</h2>
                </div>
                <div className="p-3 flex-1">
                  <div className="space-y-1">
                    {typeCats.map(parent => (
                      <div key={parent.id}>
                        <div className="group flex items-center justify-between rounded-2xl border border-transparent p-3 transition-colors hover:border-border/60 hover:bg-muted/30">
                          <div className="flex items-center gap-3">
                            <button
                              onClick={() => toggleExpand(parent.id)}
                              className={`p-0.5 rounded hover:bg-muted ${!parent.subcategories?.length ? 'invisible' : ''}`}
                            >
                              {expandedParents[parent.id] ? <ChevronDown className="w-4 h-4 text-muted-foreground" /> : <ChevronRight className="w-4 h-4 text-muted-foreground" />}
                            </button>
                            <div className="w-8 h-8 rounded-lg flex items-center justify-center text-lg" style={{ background: `${parent.color}20` }}>
                              <span>{parent.icon}</span>
                            </div>
                            <span className="font-medium">{parent.name}</span>
                          </div>
                          <div className="flex items-center gap-1 opacity-100 sm:opacity-0 sm:group-hover:opacity-100 transition-opacity">
                            <button onClick={() => { setForm({ name: '', type: parent.type, icon: '≡ƒôª', color: parent.color, parent_id: parent.id }); setShowForm(true); }}
                              className="p-1.5 rounded-lg hover:bg-muted text-muted-foreground hover:text-primary transition-colors" title="Add Sub-category">
                              <Plus className="w-3.5 h-3.5" />
                            </button>
                            <button onClick={() => { setEditingCategory(parent); setForm({ name: parent.name, type: parent.type, icon: parent.icon, color: parent.color, parent_id: '' }); setShowForm(true); }}
                              className="p-1.5 rounded-lg hover:bg-muted text-muted-foreground hover:text-foreground transition-colors">
                              <Edit3 className="w-3.5 h-3.5" />
                            </button>
                            <button onClick={() => deleteCategory(parent.id)}
                              className="p-1.5 rounded-lg hover:bg-destructive/10 text-muted-foreground hover:text-destructive transition-colors">
                              <Trash2 className="w-3.5 h-3.5" />
                            </button>
                          </div>
                        </div>
                        
                        <AnimatePresence>
                          {expandedParents[parent.id] && parent.subcategories && parent.subcategories.length > 0 && (
                            <motion.div
                              initial={{ height: 0, opacity: 0 }}
                              animate={{ height: 'auto', opacity: 1 }}
                              exit={{ height: 0, opacity: 0 }}
                              className="overflow-hidden pl-9"
                            >
                              {parent.subcategories.map((sub: any) => (
                                <div key={sub.id} className="relative mt-1 flex items-center justify-between rounded-2xl p-2 transition-colors hover:bg-muted/40 group">
                                  <div className="absolute left-[-12px] top-1/2 w-4 h-px bg-border -translate-y-1/2" />
                                  <div className="absolute left-[-12px] top-0 bottom-1/2 w-px bg-border" />
                                  
                                  <div className="flex items-center gap-2">
                                    <div className="w-6 h-6 rounded flex items-center justify-center text-sm" style={{ background: `${sub.color}20` }}>
                                      <span>{sub.icon}</span>
                                    </div>
                                    <span className="text-sm">{sub.name}</span>
                                  </div>
                                  <div className="flex items-center gap-1 opacity-100 sm:opacity-0 sm:group-hover:opacity-100 transition-opacity">
                                    <button onClick={() => { setEditingCategory(sub as any); setForm({ name: sub.name, type: parent.type, icon: sub.icon, color: sub.color, parent_id: parent.id }); setShowForm(true); }}
                                      className="p-1 rounded-md hover:bg-muted text-muted-foreground hover:text-foreground transition-colors">
                                      <Edit3 className="w-3 h-3" />
                                    </button>
                                    <button onClick={() => deleteCategory(sub.id)}
                                      className="p-1 rounded-md hover:bg-destructive/10 text-muted-foreground hover:text-destructive transition-colors">
                                      <Trash2 className="w-3 h-3" />
                                    </button>
                                  </div>
                                </div>
                              ))}
                            </motion.div>
                          )}
                        </AnimatePresence>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* Form Modal */}
      {showForm && (
        <div className="fixed inset-0 z-50 flex items-end justify-center bg-background/80 p-0 backdrop-blur-sm md:items-center md:p-4" onClick={() => setShowForm(false)}>
          <motion.div
            className="w-full max-w-sm rounded-t-[28px] border border-border bg-card p-6 shadow-xl md:rounded-[28px]"
            initial={{ opacity: 0, scale: 0.95, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            onClick={e => e.stopPropagation()}
          >
            <h2 className="text-lg font-bold mb-5">{editingCategory ? 'Edit Category' : 'New Category'}</h2>
            <div className="space-y-4">
              <div>
                <label className="text-sm font-medium mb-1 block">Name</label>
                <input value={form.name} onChange={e => setForm({ ...form, name: e.target.value })}
                  className="w-full px-3 py-2 rounded-lg border border-input bg-background text-sm focus:outline-none focus:ring-2 focus:ring-primary/20"
                  placeholder="e.g. Groceries" autoFocus />
              </div>
              
              {!form.parent_id && !editingCategory?.parent_id && (
                <div>
                  <label className="text-sm font-medium mb-1 block">Type</label>
                  <div className="grid grid-cols-3 gap-2">
                    {['expense', 'income', 'transfer'].map(t => (
                      <button key={t} onClick={() => setForm({ ...form, type: t as CategoryType })}
                        className={`py-1.5 rounded-lg border text-xs font-medium capitalize transition-all ${form.type === t ? 'border-primary bg-primary/5 text-primary' : 'border-input text-muted-foreground hover:border-primary/50'}`}>
                        {t}
                      </button>
                    ))}
                  </div>
                </div>
              )}

              <div>
                <label className="text-sm font-medium mb-1 block">Parent Category (Optional)</label>
                <select value={form.parent_id} onChange={e => setForm({ ...form, parent_id: e.target.value })}
                  className="w-full px-3 py-2 rounded-lg border border-input bg-background text-sm focus:outline-none focus:ring-2 focus:ring-primary/20">
                  <option value="">None (Top-Level)</option>
                  {getParentOptions(form.type).filter(c => c.id !== editingCategory?.id).map(c => (
                    <option key={c.id} value={c.id}>{c.name}</option>
                  ))}
                </select>
                <p className="text-[10px] text-muted-foreground mt-1">Nesting allows you to create sub-categories.</p>
              </div>

              <div className="grid grid-cols-2 gap-3">
                <div>
                  <EmojiPicker value={form.icon} onChange={val => setForm({ ...form, icon: val })} label="Icon" size="md" />
                </div>
                <div>
                  <label className="text-sm font-medium mb-2 block">Color</label>
                  <div className="flex flex-wrap gap-1.5">
                    {ACCOUNT_COLORS.slice(0, 8).map(c => (
                      <button key={c} onClick={() => setForm(f => ({ ...f, color: c }))}
                        className={`w-5 h-5 rounded-full transition-all ${form.color === c ? 'scale-125 ring-2 ring-offset-1 ring-primary' : 'hover:scale-110'}`}
                        style={{ background: c }} />
                    ))}
                  </div>
                </div>
              </div>

              <div className="flex gap-3 pt-2">
                <button onClick={() => { setShowForm(false); setEditingCategory(null); }} className="flex-1 px-4 py-2 rounded-lg border border-input text-sm font-medium hover:bg-muted">Cancel</button>
                <button onClick={saveCategory} disabled={saving} className="flex-1 px-4 py-2 rounded-lg bg-primary text-primary-foreground text-sm font-medium hover:bg-primary/90 disabled:opacity-60">
                  {saving ? 'Saving...' : 'Save'}
                </button>
              </div>
            </div>
          </motion.div>
        </div>
      )}
    </div>
  );
}

'use client';

import { useMemo, useState, useEffect, useCallback } from 'react';
import dynamic from 'next/dynamic';
import { motion } from 'framer-motion';
import {
  TrendUp, TrendDown, Wallet, ArrowsLeftRight,
  Brain, Target, Sparkle, Crown
} from '@phosphor-icons/react';
import Link from 'next/link';
import { format, parseISO } from 'date-fns';
import { formatCurrency, formatRelativeDate } from '@/lib/utils';
import type { Profile, Transaction, Account } from '@/types';

const AreaChartCard = dynamic(() => import('@/components/ui/chartjs-components').then(m => ({ default: m.AreaChartCard })), { ssr: false });
const LineChartCard = dynamic(() => import('@/components/ui/chartjs-components').then(m => ({ default: m.LineChartCard })), { ssr: false });
const DoughnutChartCard = dynamic(() => import('@/components/ui/chartjs-components').then(m => ({ default: m.DoughnutChartCard })), { ssr: false });

interface Props {
  transactions: Transaction[];
  prevTransactions: { type: string; amount: number }[];
  accounts: Account[];
  trendData: { type: string; amount: number; transaction_date: string; currency: string }[];
  profile: Profile | null;
  currentMonth: string;
  flags?: { showAI?: boolean; showDailyChart?: boolean; showInsights?: boolean };
}

const fadeUp = { initial: { opacity: 0, y: 16 }, animate: { opacity: 1, y: 0 } };
const stagger = { animate: { transition: { staggerChildren: 0.06 } } };

const CHART_PALETTE = [
  '#10b981', '#3b82f6', '#a855f7', '#f59e0b',
  '#ef4444', '#06b6d4', '#ec4899', '#64748b',
];

export function DashboardClient({ transactions, prevTransactions, accounts, trendData, profile, currentMonth, flags }: Props) {
  const currency = profile?.default_currency || 'USD';
  const [exchangeRates, setExchangeRates] = useState<Record<string, number>>({});
  const [insight, setInsight] = useState<string | null>(null);
  const [liveTransactions, setLiveTransactions] = useState<Transaction[]>(transactions);
  const [liveAccounts, setLiveAccounts] = useState<Account[]>(accounts);
  const [refreshing, setRefreshing] = useState(false);

  const refreshDashboard = useCallback(async () => {
    setRefreshing(true);
    try {
      const [txRes, accRes] = await Promise.all([
        fetch('/api/transactions?limit=50').then(r => r.json()),
        fetch('/api/accounts').then(r => r.json()),
      ]);
      if (txRes.data) setLiveTransactions(txRes.data);
      if (accRes.data) setLiveAccounts(accRes.data);
    } catch {
      // Keep the current screen state if background refresh fails.
    } finally {
      setRefreshing(false);
    }
  }, []);

  useEffect(() => {
    const handler = () => refreshDashboard();
    window.addEventListener('dashboardRefresh', handler);
    return () => window.removeEventListener('dashboardRefresh', handler);
  }, [refreshDashboard]);

  useEffect(() => { setLiveTransactions(transactions); }, [transactions]);
  useEffect(() => { setLiveAccounts(accounts); }, [accounts]);

  useEffect(() => {
    fetch(`/api/exchange-rates?base=${currency}`)
      .then(res => res.json())
      .then(data => { if (data.rates) setExchangeRates(data.rates); })
      .catch(console.error);

    if (profile?.subscription_tier !== 'free' || process.env.NODE_ENV === 'development') {
      fetch('/api/ai/insights')
        .then(r => r.json())
        .then(data => { if (data.insight) setInsight(data.insight); })
        .catch(console.error);
    }
  }, [currency, profile?.subscription_tier]);

  const convert = useCallback((amount: number, fromCurr: string) => {
    if (!fromCurr || fromCurr === currency || !exchangeRates[fromCurr]) return amount;
    return amount / exchangeRates[fromCurr];
  }, [currency, exchangeRates]);

  const stats = useMemo(() => {
    const income = liveTransactions.filter(tx => tx.type === 'income').reduce((sum, tx) => sum + convert(tx.amount, tx.currency || 'USD'), 0);
    const expenses = liveTransactions.filter(tx => tx.type === 'expense').reduce((sum, tx) => sum + convert(tx.amount, tx.currency || 'USD'), 0);
    const prevIncome = prevTransactions.filter(tx => tx.type === 'income').reduce((sum, tx) => sum + convert(tx.amount, (tx as { currency?: string }).currency || 'USD'), 0);
    const prevExpenses = prevTransactions.filter(tx => tx.type === 'expense').reduce((sum, tx) => sum + convert(tx.amount, (tx as { currency?: string }).currency || 'USD'), 0);
    const totalBalance = liveAccounts.reduce((sum, account) => sum + convert(account.balance, account.currency || 'USD'), 0);
    const savingsRate = income > 0 ? Math.round(((income - expenses) / income) * 100) : 0;
    const incomePct = prevIncome > 0 ? ((income - prevIncome) / prevIncome) * 100 : 0;
    const expensePct = prevExpenses > 0 ? ((expenses - prevExpenses) / prevExpenses) * 100 : 0;

    return {
      income,
      expenses,
      totalBalance,
      savingsRate,
      incomePct,
      expensePct,
      net: income - expenses,
    };
  }, [convert, liveAccounts, liveTransactions, prevTransactions]);

  const categoryData = useMemo(() => {
    const grouped: Record<string, { name: string; icon: string; color: string; total: number; count: number }> = {};

    liveTransactions.filter(tx => tx.type === 'expense').forEach(tx => {
      const category = tx.category;
      const key = category?.id || 'uncategorized';
      if (!grouped[key]) {
        grouped[key] = {
          name: category?.name || 'Uncategorized',
          icon: category?.icon || '≡ƒôª',
          color: category?.color || '#94a3b8',
          total: 0,
          count: 0,
        };
      }

      grouped[key].total += convert(tx.amount, tx.currency || 'USD');
      grouped[key].count += 1;
    });

    return Object.values(grouped)
      .sort((a, b) => b.total - a.total)
      .slice(0, 8)
      .map((item, index) => ({
        ...item,
        percentage: stats.expenses > 0 ? Math.round((item.total / stats.expenses) * 100) : 0,
        fill: item.color || CHART_PALETTE[index % CHART_PALETTE.length],
      }));
  }, [convert, liveTransactions, stats.expenses]);

  const trendChartData = useMemo(() => {
    const monthly: Record<string, { month: string; label: string; income: number; expenses: number }> = {};

    trendData.forEach(tx => {
      const key = tx.transaction_date.slice(0, 7);
      if (!monthly[key]) {
        monthly[key] = {
          month: key,
          label: format(parseISO(`${key}-01`), 'MMM'),
          income: 0,
          expenses: 0,
        };
      }

      if (tx.type === 'income') monthly[key].income += convert(tx.amount, tx.currency || 'USD');
      if (tx.type === 'expense') monthly[key].expenses += convert(tx.amount, tx.currency || 'USD');
    });

    return Object.values(monthly).sort((a, b) => a.month.localeCompare(b.month));
  }, [convert, trendData]);

  const dailyData = useMemo(() => {
    const daily: Record<string, number> = {};

    liveTransactions.filter(tx => tx.type === 'expense').forEach(tx => {
      const day = tx.transaction_date.slice(0, 10);
      daily[day] = (daily[day] || 0) + convert(tx.amount, tx.currency || 'USD');
    });

    return Object.entries(daily)
      .sort(([a], [b]) => a.localeCompare(b))
      .map(([date, amount]) => ({ date: format(parseISO(date), 'MMM d'), amount }));
  }, [convert, liveTransactions]);

  const recentTransactions = liveTransactions.slice(0, 8);
  const fmtCompact = (value: number) => formatCurrency(value, currency, { compact: true });

  return (
    <div className="space-y-3 md:space-y-5">
      {/* ΓöÇΓöÇΓöÇ Hero Balance Card ΓöÇΓöÇΓöÇ */}
      <motion.section
        className="glass-card overflow-hidden"
        initial={{ opacity: 0, y: 10 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.4, ease: [0.4, 0, 0.2, 1] }}
      >
        <div className="p-4 md:p-6">
          <p className="text-[10px] font-medium uppercase tracking-[0.2em] text-muted-foreground">{currentMonth}</p>
          <h2 className="mt-1.5 text-2xl font-serif font-bold tracking-tight md:text-4xl">{formatCurrency(stats.totalBalance, currency)}</h2>
          <p className="mt-1 text-xs text-muted-foreground">
            {liveAccounts.length} account{liveAccounts.length === 1 ? '' : 's'}
