            </motion.div>
          );
        })}
      </motion.div>

      {/* ΓöÇΓöÇΓöÇ Charts Row ΓöÇΓöÇΓöÇ */}
      <div className="grid grid-cols-1 gap-3 md:gap-4 xl:grid-cols-[1.2fr_0.8fr]">
