                ))}
              </div>
            </>
          ) : (
            <div className="flex h-[200px] flex-col items-center justify-center text-center text-muted-foreground">
              <Target className="mb-2 h-8 w-8 opacity-20" weight="light" />
              <p className="text-xs">Categories appear when you add expenses</p>
            </div>
          )}
        </motion.section>
      </div>

      {/* ΓöÇΓöÇΓöÇ Daily Spending ΓÇö Line Chart (was bar) ΓöÇΓöÇΓöÇ */}
      {dailyData.length > 0 && (
        <motion.section className="glass-card p-4 md:p-5" initial={{ opacity: 0, y: 14 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.2 }}>
          <div className="mb-4 flex items-center justify-between">
            <div>
              <h3 className="text-sm font-semibold text-foreground">Daily Spending</h3>
              <p className="text-[10px] text-muted-foreground">This month&apos;s rhythm</p>
            </div>
            <span className="text-[10px] text-muted-foreground">{dailyData.length} days</span>
          </div>
          <LineChartCard
            labels={dailyData.map(item => item.date)}
            data={dailyData.map(item => item.amount)}
            color="#10b981"
            formatValue={fmtCompact}
            height={160}
          />
        </motion.section>
      )}

      {/* ΓöÇΓöÇΓöÇ Accounts + Recent Transactions ΓöÇΓöÇΓöÇ */}
      <div className="grid grid-cols-1 gap-3 md:gap-4 xl:grid-cols-2">
        {/* Accounts ΓÇö flat list */}
        <motion.section className="glass-card overflow-hidden" initial={{ opacity: 0, y: 14 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.25 }}>
          <div className="flex items-center justify-between px-4 pt-4 pb-1">
            <div>
              <h3 className="text-sm font-semibold text-foreground">Accounts</h3>
              <p className="text-[10px] text-muted-foreground">Your wallets</p>
            </div>
            <Link href="/dashboard/accounts" className="text-[10px] font-medium text-primary">All</Link>
          </div>
          {liveAccounts.length > 0 ? (
            <div>
              {liveAccounts.slice(0, 5).map((account) => (
                <div key={account.id} className="flat-list-item">
                  <div className="flat-list-icon" style={{ background: `${account.color}15` }}>
                    {account.icon}
                  </div>
                  <div className="min-w-0 flex-1">
                    <p className="truncate text-xs font-medium text-foreground">{account.name}</p>
                    <p className="text-[10px] capitalize text-muted-foreground">{account.type}</p>
                  </div>
                  <p className={`text-xs font-semibold tabular-nums ${account.balance >= 0 ? 'text-foreground' : 'text-red-500'}`}>
                    {formatCurrency(account.balance, account.currency)}
                  </p>
                </div>
              ))}
            </div>
          ) : (
            <div className="px-4 py-8 text-center text-muted-foreground">
              <Wallet className="mx-auto mb-2 h-7 w-7 opacity-25" weight="light" />
              <p className="text-xs">No accounts yet</p>
            </div>
          )}
        </motion.section>

        {/* Recent Transactions ΓÇö flat list */}
        <motion.section className="glass-card overflow-hidden" initial={{ opacity: 0, y: 14 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.3 }}>
          <div className="flex items-center justify-between px-4 pt-4 pb-1">
            <div>
              <h3 className="text-sm font-semibold text-foreground">Recent</h3>
              <p className="text-[10px] text-muted-foreground">Latest activity</p>
            </div>
            <Link href="/dashboard/transactions" className="text-[10px] font-medium text-primary">All</Link>
          </div>
          {recentTransactions.length > 0 ? (
            <div>
              {recentTransactions.map((tx) => (
                <div key={tx.id} className="flat-list-item">
                  <div className="flat-list-icon">
                    {tx.category?.icon || (tx.type === 'income' ? '≡ƒÆ░' : tx.type === 'transfer' ? 'Γåö∩╕Å' : '≡ƒÆ╕')}
                  </div>
                  <div className="min-w-0 flex-1">
                    <p className="truncate text-xs font-medium text-foreground">{tx.description || tx.category?.name || 'Transaction'}</p>
                    <p className="text-[10px] text-muted-foreground">{formatRelativeDate(tx.transaction_date)}</p>
                  </div>
                  <p className={`text-xs font-semibold tabular-nums ${tx.type === 'income' ? 'text-emerald-500' : tx.type === 'expense' ? 'text-red-500' : 'text-primary'}`}>
                    {tx.type === 'income' ? '+' : tx.type === 'expense' ? '-' : ''}
                    {formatCurrency(tx.amount, tx.currency)}
                  </p>
                </div>
              ))}
            </div>
          ) : (
            <div className="px-4 py-8 text-center text-muted-foreground">
              <ArrowsLeftRight className="mx-auto mb-2 h-7 w-7 opacity-25" weight="light" />
              <p className="text-xs">No transactions yet</p>
            </div>
          )}
        </motion.section>
      </div>

      {/* ΓöÇΓöÇΓöÇ Empty State CTA ΓöÇΓöÇΓöÇ */}
      {transactions.length === 0 && (
        <motion.section
          className="glass-card flex items-start gap-3 p-4"
          style={{ borderColor: 'hsl(var(--primary) / 0.1)' }}
          initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 0.35 }}
        >
          <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-xl bg-primary/10 text-primary">
            <Brain className="h-5 w-5" weight="duotone" />
          </div>
          <div>
            <h3 className="text-sm font-semibold text-foreground">Start with one message</h3>
            <p className="mt-0.5 text-xs leading-relaxed text-muted-foreground">
              Say something like &ldquo;I spent Γé▒150 on lunch&rdquo; and CashBash will log it for you.
            </p>
            <Link href="/dashboard/ai-assistant">
              <motion.span className="mt-3 inline-flex items-center gap-1.5 rounded-xl bg-primary px-3 py-1.5 text-xs font-medium text-primary-foreground" whileTap={{ scale: 0.97 }}>
                <Brain className="h-3.5 w-3.5" weight="regular" /> Open AI
              </motion.span>
            </Link>
          </div>
        </motion.section>
      )}
    </div>
  );
}

'use client';

import { useState, useEffect, useRef, useCallback } from 'react';
import { Download, Upload, CheckCircle2, Loader2, FileWarning, Trash2, Edit2, Check, X } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { toast } from 'sonner';
import Papa from 'papaparse';
import { createWorker, PSM } from 'tesseract.js';
import { ParsedTransaction } from '@/lib/smart-parser';

export default function ImportExportPage() {
  const [accounts, setAccounts] = useState<any[]>([]);
  const [selectedAccountId, setSelectedAccountId] = useState('');
  const [importing, setImporting] = useState(false);
  const [extracting, setExtracting] = useState(false);
  const [progress, setProgress] = useState(0);
  const [statusText, setStatusText] = useState('');

  const [extractedTransactions, setExtractedTransactions] = useState<ParsedTransaction[]>([]);
  const [editingIndex, setEditingIndex] = useState<number | null>(null);
  const [editForm, setEditForm] = useState<ParsedTransaction | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    fetch('/api/accounts').then(r => r.json()).then(res => {
      setAccounts(res.data || []);
      if (res.data?.length > 0) setSelectedAccountId(res.data[0].id);
    });
  }, []);

  const handleExport = () => {
    window.location.href = '/api/export';
    toast.success('Export started!');
  };

  const processCSV = (file: File) => {
    setStatusText('Parsing CSV...');
    Papa.parse(file, {
      header: true,
      skipEmptyLines: true,
      complete: (results) => {
        try {
          const txs: ParsedTransaction[] = results.data.map((row: any) => {
            const amountStr = row.Amount || row.amount || '0';
            const amountNum = parseFloat(amountStr.replace(/[^0-9.-]/g, ''));
            const isExpense = amountNum < 0 || (row.Type?.toLowerCase() === 'expense');

            return {
              date: row.Date || row.date || new Date().toISOString().split('T')[0],
              description: row.Description || row.description || row.Payee || 'Imported CSV',
              amount: Math.round(Math.abs(amountNum) * 100),
              currency: row.Currency || row.currency || 'USD',
              type: isExpense ? 'expense' : 'income'
            };
          });
          setExtractedTransactions(txs);
          setExtracting(false);
          toast.success(`Found ${txs.length} transactions`);
        } catch (err: any) {
          toast.error('Failed to parse CSV format');
          setExtracting(false);
        }
      },
      error: (error) => {
        toast.error(`CSV error: ${error.message}`);
        setExtracting(false);
      }
    });
  };

  const processImage = async (file: File) => {
    setStatusText('Loading OCR engine...');
    try {
      const worker = await createWorker('eng');

      worker.setParameters({
        tessedit_pageseg_mode: PSM.SINGLE_BLOCK // Assume uniform block of text
      });

      setStatusText('Reading image text...');
      const { data: { text } } = await worker.recognize(file);
      await worker.terminate();

      setStatusText('Extracting transactions...');
      // Use our backend smart-parser logic here if we exposed it or fetch to backend
      const formData = new FormData();
      // create a text file out of the OCR text to send to backend parser
      const textFile = new File([text], 'ocr.txt', { type: 'text/plain' });
      formData.append('file', textFile);

      const res = await fetch('/api/import/extract', {
        method: 'POST',
        body: formData
      });
      const data = await res.json();

      if (!res.ok) throw new Error(data.error);

      setExtractedTransactions(data.transactions || []);
      toast.success(`Found ${data.transactions?.length || 0} transactions`);
    } catch (err: any) {
      toast.error(err.message || 'Failed to process image');
    } finally {
      setExtracting(false);
    }
  };

  const processPDF = async (file: File) => {
    setStatusText('Extracting PDF text...');
    try {
      const formData = new FormData();
      formData.append('file', file);

      const res = await fetch('/api/import/extract', {
        method: 'POST',
        body: formData
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data.error);

      setExtractedTransactions(data.transactions || []);
      toast.success(`Found ${data.transactions?.length || 0} transactions`);
    } catch (err: any) {
      toast.error(err.message || 'Failed to process PDF');
    } finally {
      setExtracting(false);
    }
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !selectedAccountId) return;

    setExtracting(true);
    setExtractedTransactions([]);
    setProgress(0);

    const type = file.type;
    const name = file.name.toLowerCase();

    if (type === 'text/csv' || name.endsWith('.csv')) {
      processCSV(file);
    } else if (type === 'application/pdf' || name.endsWith('.pdf')) {
      processPDF(file);
    } else if (type.startsWith('image/') || name.match(/\.(jpg|jpeg|png|webp)$/)) {
      await processImage(file);
    } else {
      toast.error('Unsupported file type. Use CSV, PDF, or Images.');
      setExtracting(false);
    }

    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleImportAll = async () => {
    if (extractedTransactions.length === 0) return;

    setImporting(true);
    try {
      // The API expects amount to be un-multiplied (it will multiply by 100) OR we modify the API.
      // Wait, our API does: Math.round(Math.abs(amountFloat) * 100).
      // Since our parser already returned cents, we must pass it formatted as a string decimal for the current API to ingest properly.
      const formattedTxs = extractedTransactions.map(t => ({
        date: t.date,
        description: t.description,
        amount: (t.amount / 100).toFixed(2), // convert back to decimal for the API
        currency: t.currency,
        type: t.type
      }));

      const res = await fetch('/api/import', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ account_id: selectedAccountId, transactions: formattedTxs })
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data.error);

      toast.success(`Successfully imported ${data.count} transactions!`);
      setExtractedTransactions([]);
    } catch (err: any) {
      toast.error(err.message || 'Failed to import');
    } finally {
      setImporting(false);
    }
  };

  const deleteRow = (index: number) => {
    setExtractedTransactions(prev => prev.filter((_, i) => i !== index));
  };

  const startEdit = (index: number) => {
    setEditingIndex(index);
    setEditForm({ ...extractedTransactions[index] });
  };

  const saveEdit = () => {
    if (editingIndex === null || !editForm) return;
    setExtractedTransactions(prev => {
      const nw = [...prev];
      nw[editingIndex] = editForm;
      return nw;
    });
    setEditingIndex(null);
    setEditForm(null);
  };

  return (
    <div className="max-w-5xl mx-auto space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold">Smart Import / Export</h1>
          <p className="text-sm text-muted-foreground">Extract transactions from CSV, PDF, or Images (Zero AI Cost)</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="rounded-2xl border border-border bg-card shadow-soft p-8 flex flex-col items-center justify-center text-center relative overflow-hidden"
        >
          {extracting && (
            <div className="absolute inset-0 bg-background/80 backdrop-blur-sm z-10 flex flex-col items-center justify-center">
              <Loader2 className="w-8 h-8 animate-spin text-primary mb-4" />
              <p className="font-medium">{statusText}</p>
            </div>
          )}

          <div className="w-16 h-16 rounded-full bg-primary/10 flex items-center justify-center mb-4">
            <Upload className="w-8 h-8 text-primary" />
          </div>
          <h2 className="text-xl font-semibold mb-2">Smart Import</h2>
          <p className="text-muted-foreground mb-4 text-sm">
            Upload a CSV, PDF bank statement, or Receipt Image. We'll extract the data automatically.
          </p>
          <div className="w-full text-left mb-6 space-y-1">
            <label className="text-sm font-medium">Target Account</label>
            <select value={selectedAccountId} onChange={e => setSelectedAccountId(e.target.value)}
              className="w-full px-3 py-2 rounded-lg border border-input bg-background focus:outline-none focus:ring-2 focus:ring-primary/20">
              {accounts.map(a => <option key={a.id} value={a.id}>{a.name} ({a.currency})</option>)}
            </select>
          </div>
          <input type="file" accept=".csv,.pdf,image/*" className="hidden" ref={fileInputRef} onChange={handleFileChange} />
          <button 
            onClick={() => fileInputRef.current?.click()}
            disabled={extracting || accounts.length === 0}
            className="w-full flex justify-center items-center gap-2 py-2.5 rounded-xl bg-primary text-primary-foreground text-sm font-medium hover:bg-primary/90 transition-all hover:shadow-glow disabled:opacity-50">
            Select File
          </button>
        </motion.div>

        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.1 }}
          className="rounded-2xl border border-border bg-card shadow-soft p-8 flex flex-col items-center justify-center text-center"
        >
          <div className="w-16 h-16 rounded-full bg-primary/10 flex items-center justify-center mb-4">
            <Download className="w-8 h-8 text-primary" />
          </div>
          <h2 className="text-xl font-semibold mb-2">Export Data</h2>
          <p className="text-muted-foreground mb-6 text-sm">
            Download all your transaction data as a CSV file for your own records.
          </p>
          <button onClick={handleExport} className="w-full py-2.5 rounded-xl border border-input text-sm font-medium hover:bg-muted transition-colors mt-auto">
            Export All Data
          </button>
        </motion.div>
      </div>

      <AnimatePresence>
        {extractedTransactions.length > 0 && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            className="rounded-2xl border border-border bg-card shadow-soft overflow-hidden"
          >
            <div className="p-4 border-b border-border flex items-center justify-between bg-muted/30">
              <div>
                <h3 className="font-semibold">Review Extracted Data</h3>
                <p className="text-sm text-muted-foreground">Found {extractedTransactions.length} transactions. Edit or remove before importing.</p>
              </div>
              <div className="flex gap-2">
                <button 
                  onClick={() => setExtractedTransactions([])}
                  className="px-4 py-2 rounded-lg text-sm font-medium border border-input hover:bg-muted"
                >
                  Cancel
                </button>
                <button 
                  onClick={handleImportAll}
                  disabled={importing}
                  className="px-4 py-2 rounded-lg text-sm font-medium bg-primary text-primary-foreground hover:bg-primary/90 flex items-center gap-2"
                >
                  {importing ? <Loader2 className="w-4 h-4 animate-spin"/> : <CheckCircle2 className="w-4 h-4" />}
                  Confirm Import
                </button>
              </div>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-sm text-left">
                <thead className="text-xs text-muted-foreground bg-muted/50 uppercase">
                  <tr>
                    <th className="px-4 py-3">Date</th>
                    <th className="px-4 py-3">Description</th>
                    <th className="px-4 py-3">Amount</th>
                    <th className="px-4 py-3">Type</th>
                    <th className="px-4 py-3 text-right">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-border">
                  {extractedTransactions.map((tx, idx) => (
                    <tr key={idx} className="hover:bg-muted/30">
                      {editingIndex === idx && editForm ? (
                        <>
                          <td className="px-4 py-2"><input type="date" value={editForm.date} onChange={e => setEditForm({...editForm, date: e.target.value})} className="w-full bg-background border rounded px-2 py-1" /></td>
                          <td className="px-4 py-2"><input type="text" value={editForm.description} onChange={e => setEditForm({...editForm, description: e.target.value})} className="w-full bg-background border rounded px-2 py-1" /></td>
                          <td className="px-4 py-2">
                            <div className="flex items-center gap-1">
                              {editForm.currency} <input type="number" step="0.01" value={(editForm.amount/100).toFixed(2)} onChange={e => setEditForm({...editForm, amount: Math.round(parseFloat(e.target.value)*100)})} className="w-20 bg-background border rounded px-2 py-1" />
                            </div>
                          </td>
                          <td className="px-4 py-2">
                            <select value={editForm.type} onChange={e => setEditForm({...editForm, type: e.target.value as any})} className="bg-background border rounded px-2 py-1">
                              <option value="expense">Expense</option>
                              <option value="income">Income</option>
                            </select>
                          </td>
                          <td className="px-4 py-2 text-right">
                            <button onClick={saveEdit} className="text-green-500 p-1"><Check className="w-4 h-4"/></button>
                            <button onClick={() => setEditingIndex(null)} className="text-red-500 p-1"><X className="w-4 h-4"/></button>
                          </td>
                        </>
                      ) : (
                        <>
                          <td className="px-4 py-3 font-mono">{tx.date}</td>
                          <td className="px-4 py-3 max-w-[200px] truncate" title={tx.description}>{tx.description}</td>
                          <td className={`px-4 py-3 font-mono font-medium ${tx.type === 'income' ? 'text-emerald-500' : 'text-red-500'}`}>
                            {tx.type === 'income' ? '+' : '-'}{(tx.amount/100).toFixed(2)} {tx.currency}
                          </td>
                          <td className="px-4 py-3 capitalize">{tx.type}</td>
                          <td className="px-4 py-3 text-right">
                            <button onClick={() => startEdit(idx)} className="text-muted-foreground hover:text-primary p-1 inline-block"><Edit2 className="w-4 h-4"/></button>
                            <button onClick={() => deleteRow(idx)} className="text-muted-foreground hover:text-red-500 p-1 inline-block"><Trash2 className="w-4 h-4"/></button>
                          </td>
                        </>
                      )}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useTheme } from 'next-themes';
import { motion } from 'framer-motion';
import {
  Gear, Coins, LockSimple, Calculator, Desktop,
  ArrowCounterClockwise, EnvelopeSimple, Question, ThumbsUp,
  CaretLeft, Moon, Sun, SunDim, SignOut, Brain,
  CreditCard, Bell, ShieldCheck, FileArrowDown, FileArrowUp,
  Tag, Repeat, Target, ChartLineUp, UserCircle,
  Palette, Globe, Clock, CalendarBlank
} from '@phosphor-icons/react';
import { toast } from 'sonner';
import { CURRENCIES } from '@/lib/utils';

// 4├ù3 grid ΓÇö CashBash features + reference-inspired items
const SETTINGS_ITEMS = [
  { id: 'configuration', icon: Gear, label: 'Configuration' },
  { id: 'accounts', icon: Coins, label: 'Accounts', href: '/dashboard/accounts' },
  { id: 'categories', icon: Tag, label: 'Categories', href: '/dashboard/categories' },
  { id: 'budgets', icon: Target, label: 'Budgets', href: '/dashboard/budgets' },
  { id: 'bills', icon: Repeat, label: 'Recurring', href: '/dashboard/bills' },
  { id: 'goals', icon: ChartLineUp, label: 'Goals', href: '/dashboard/goals' },
  { id: 'passcode', icon: LockSimple, label: 'Passcode' },
  { id: 'ai', icon: Brain, label: 'AI Settings' },
  { id: 'billing', icon: CreditCard, label: 'Billing' },
  { id: 'backup', icon: ArrowCounterClockwise, label: 'Backup' },
  { id: 'feedback', icon: EnvelopeSimple, label: 'Feedback' },
  { id: 'help', icon: Question, label: 'Help' },
];

type ViewType = 'grid' | 'configuration' | 'passcode' | 'ai' | 'billing' | 'appearance' | 'profile' | 'notifications';

export default function SettingsPage() {
  const router = useRouter();
  const { theme, setTheme } = useTheme();
  const [view, setView] = useState<ViewType>('grid');
  const [loading, setLoading] = useState(false);
  const [pinInput, setPinInput] = useState('');
  const [hasPin, setHasPin] = useState(false);
  const [profile, setProfile] = useState({
    display_name: '',
    default_currency: 'USD',
    timezone: 'UTC',
    locale: 'en',
    date_format: 'YYYY-MM-DD',
    first_day_of_week: 0,
    monthly_budget: '',
    weekly_budget: '',
    ai_enabled: true,
    ai_auto_categorize: true,
    ai_suggestions: true,
    show_balance: true,
    compact_mode: false,
    subscription_tier: 'free',
  });

  useEffect(() => {
    setHasPin(!!localStorage.getItem('app_pin'));
    fetchProfile();
  }, []);

  const fetchProfile = async () => {
    try {
      const res = await fetch('/api/profile');
      const data = await res.json();
      if (data.data) {
        setProfile(prev => ({
          ...prev,
          ...data.data,
          monthly_budget: data.data.monthly_budget ? (data.data.monthly_budget / 100).toString() : '',
          weekly_budget: data.data.weekly_budget ? (data.data.weekly_budget / 100).toString() : '',
          subscription_tier: data.data.subscription_tier || 'free',
        }));
      }
    } catch {}
  };

  const saveProfile = async () => {
    setLoading(true);
    try {
      const payload: Record<string, unknown> = {
        display_name: profile.display_name,
        default_currency: profile.default_currency,
        timezone: profile.timezone,
        locale: profile.locale,
        date_format: profile.date_format,
        first_day_of_week: profile.first_day_of_week,
        ai_enabled: profile.ai_enabled,
        ai_auto_categorize: profile.ai_auto_categorize,
        ai_suggestions: profile.ai_suggestions,
        monthly_budget: profile.monthly_budget ? Math.round(parseFloat(profile.monthly_budget) * 100) : null,
        weekly_budget: profile.weekly_budget ? Math.round(parseFloat(profile.weekly_budget) * 100) : null,
      };
      const res = await fetch('/api/profile', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });
      if (res.ok) toast.success('Settings saved!');
      else toast.error('Failed to save');
    } catch { toast.error('Failed to save'); }
    finally { setLoading(false); }
  };

  const exportData = async () => {
    try {
      const res = await fetch('/api/export');
      const blob = await res.blob();
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `cashbash-export-${new Date().toISOString().slice(0, 10)}.csv`;
      a.click();
      toast.success('Export started!');
    } catch { toast.error('Export failed'); }
  };

  const handleManageBilling = async () => {
    setLoading(true);
    try {
      const res = await fetch('/api/portal', { method: 'POST' });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error);
      if (data.url) window.location.href = data.url;
    } catch (err: any) { toast.error(err.message || 'Failed'); }
    finally { setLoading(false); }
  };

  const savePin = () => {
    if (pinInput.length !== 4) return toast.error('PIN must be 4 digits');
    localStorage.setItem('app_pin', pinInput);
    setHasPin(true); setPinInput('');
    toast.success('App Lock PIN saved');
  };
  const removePin = () => {
    localStorage.removeItem('app_pin');
    setHasPin(false);
    toast.success('PIN removed');
  };

  const update = (key: string, value: unknown) => setProfile(p => ({ ...p, [key]: value }));
  const toggle = (key: string) => setProfile(p => ({ ...p, [key]: !(p as Record<string, unknown>)[key] }));

  const handleGridClick = (id: string, href?: string) => {
    if (href) { router.push(href); return; }
    if (['configuration', 'passcode', 'ai', 'billing', 'appearance', 'profile', 'notifications'].includes(id)) {
      setView(id as ViewType); return;
    }
    if (id === 'backup') { exportData(); return; }
    if (id === 'feedback') { window.open('mailto:drvelu@outlook.com?subject=CashBash Feedback', '_blank'); return; }
    if (id === 'help') { toast('Help center coming soon!'); return; }
  };

  // ΓöÇΓöÇΓöÇ Back button helper ΓöÇΓöÇΓöÇ
  const BackHeader = ({ title }: { title: string }) => (
    <div className="flex items-center gap-3 px-4 py-3 border-b border-border/10">
      <button onClick={() => setView('grid')} className="p-1"><CaretLeft className="w-5 h-5" /></button>
      <h1 className="text-xl font-semibold">{title}</h1>
    </div>
  );

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // GRID VIEW
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  if (view === 'grid') {
    return (
      <div className="space-y-0 pb-24">
        {/* Header */}
        <div className="flex items-center justify-between px-4 py-3">
          <div>
            <p className="text-xs text-muted-foreground uppercase tracking-wider">CashBash.ai</p>
            <h1 className="text-2xl font-semibold">Settings</h1>
          </div>
          <span className="text-xs text-muted-foreground">v4.11.0</span>
        </div>

        {/* Profile quick info */}
        <button onClick={() => setView('profile')} className="w-full flex items-center gap-3 px-4 py-3 border-y border-border/10 active:bg-foreground/[0.02]">
          <div className="w-12 h-12 rounded-full bg-primary/10 flex items-center justify-center">
            <UserCircle className="w-7 h-7 text-primary" weight="fill" />
          </div>
          <div className="flex-1 text-left">
            <p className="text-sm font-semibold">{profile.display_name || 'Set your name'}</p>
            <p className="text-xs text-muted-foreground capitalize">{profile.subscription_tier} Plan ┬╖ {profile.default_currency}</p>
          </div>
          <CaretLeft className="w-4 h-4 text-muted-foreground rotate-180" />
        </button>

        {/* 4├ù3 grid */}
        <div className="settings-grid px-2">
          {SETTINGS_ITEMS.map(({ id, icon: Icon, label, href }) => (
            <motion.button
              key={id}
              className="settings-grid-item"
              onClick={() => handleGridClick(id, href as string)}
              whileTap={{ scale: 0.95 }}
            >
              <Icon className="icon" weight="regular" />
              <span className="label">{label}</span>
            </motion.button>
          ))}
        </div>

        {/* Quick settings below */}
        <div className="config-section-header">Quick Settings</div>

        <div className="config-item" onClick={() => setView('appearance')}>
          <div className="flex items-center gap-2.5">
            <Palette className="w-4 h-4 text-muted-foreground" />
            <span className="config-label">Appearance</span>
          </div>
          <span className="config-value capitalize">{theme}</span>
        </div>

        <div className="config-item" onClick={() => setView('notifications')}>
          <div className="flex items-center gap-2.5">
            <Bell className="w-4 h-4 text-muted-foreground" />
            <span className="config-label">Notifications</span>
          </div>
          <span className="config-value">ΓåÆ</span>
        </div>

        <div className="config-item" onClick={() => router.push('/dashboard/import-export')}>
          <div className="flex items-center gap-2.5">
            <FileArrowUp className="w-4 h-4 text-muted-foreground" />
            <span className="config-label">Import / Export</span>
          </div>
          <span className="config-value">ΓåÆ</span>
        </div>

        <div className="config-item" onClick={() => router.push('/dashboard/templates')}>
          <div className="flex items-center gap-2.5">
            <FileArrowDown className="w-4 h-4 text-muted-foreground" />
            <span className="config-label">Templates</span>
          </div>
          <span className="config-value">ΓåÆ</span>
        </div>

        <div className="config-item" onClick={() => router.push('/dashboard/tags')}>
          <div className="flex items-center gap-2.5">
            <Tag className="w-4 h-4 text-muted-foreground" />
            <span className="config-label">Tags</span>
          </div>
          <span className="config-value">ΓåÆ</span>
        </div>

        {/* Sign out */}
        <div className="mt-4 config-item" onClick={() => {
          fetch('/auth/callback?action=signout').then(() => router.push('/login'));
        }}>
          <div className="flex items-center gap-2.5">
            <SignOut className="w-4 h-4 text-red-400" />
            <span className="config-label text-red-400">Sign Out</span>
          </div>
        </div>
      </div>
    );
  }

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // PROFILE VIEW
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  if (view === 'profile') {
    return (
      <div className="space-y-0 pb-24">
        <BackHeader title="Profile" />
        <div className="px-4 space-y-0">
          <div className="underline-field">
            <label>Display Name</label>
            <input value={profile.display_name} onChange={e => update('display_name', e.target.value)} placeholder="Your name" />
          </div>
          <div className="underline-field">
            <label>Monthly Budget</label>
            <input type="number" value={profile.monthly_budget} onChange={e => update('monthly_budget', e.target.value)} placeholder="e.g. 3000" />
          </div>
          <div className="underline-field">
            <label>Weekly Budget</label>
            <input type="number" value={profile.weekly_budget} onChange={e => update('weekly_budget', e.target.value)} placeholder="e.g. 750" />
          </div>
        </div>
        <div className="config-item" onClick={() => { toggle('show_balance'); }}>
          <span className="config-label">Show Balance</span>
          <span className="config-value">{profile.show_balance ? 'ON' : 'OFF'}</span>
        </div>
        <div className="config-item" onClick={() => { toggle('compact_mode'); }}>
          <span className="config-label">Compact Mode</span>
          <span className="config-value">{profile.compact_mode ? 'ON' : 'OFF'}</span>
        </div>
        <SaveButton loading={loading} onSave={saveProfile} />
      </div>
    );
  }

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // CONFIGURATION VIEW
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  if (view === 'configuration') {
    return (
      <div className="space-y-0 pb-24">
        <BackHeader title="Configuration" />

        <div className="config-section-header">Category / Repeat</div>
        <ConfigLink label="Income Categories" onClick={() => router.push('/dashboard/categories')} />
        <ConfigLink label="Expense Categories" onClick={() => router.push('/dashboard/categories')} />
        <ConfigLink label="Budget Setting" onClick={() => router.push('/dashboard/budgets')} />
        <ConfigLink label="Recurring / Bills" onClick={() => router.push('/dashboard/bills')} />
        <ConfigLink label="Goals" onClick={() => router.push('/dashboard/goals')} />

        <div className="config-section-header">Currency & Locale</div>
        <div className="config-item">
          <span className="config-label">Main Currency</span>
          <select value={profile.default_currency}
            onChange={e => { update('default_currency', e.target.value); }}
            className="config-value bg-transparent border-none outline-none text-right cursor-pointer">
            {Object.values(CURRENCIES).map(c => (
              <option key={c.code} value={c.code}>{c.code} ({c.symbol})</option>
            ))}
          </select>
        </div>
        <div className="config-item">
          <span className="config-label">Date Format</span>
          <select value={profile.date_format}
            onChange={e => update('date_format', e.target.value)}
            className="config-value bg-transparent border-none outline-none text-right cursor-pointer">
